{
	"name": "mai-papyrusproxy",
	"displayName": "MicrosoftAI LLM Proxy",
	"description": "Universal LLM proxy supporting LiteLLM with GitHub Copilot backend, VS Code LM API, and Papyrus.",
	"publisher": "MAI-EngineeringSystems",
	"version": "1.20260330.1",
	"engines": {
		"vscode": "^1.98.0"
	},
	"categories": [
		"Other"
	],
	"activationEvents": [
		"onStartupFinished"
	],
	"main": "./dist/extension.js",
	"repository": {
		"type": "git",
		"uri": "https://dev.azure.com/msasg/Engineering%20Fundamentals/_git/engsys"
	},
	"contributes": {
		"commands": [
			{
				"command": "mai-llmproxy.startServer",
				"title": "MAI-LLMProxy: Start Server"
			},
			{
				"command": "mai-llmproxy.stopServer",
				"title": "MAI-LLMProxy: Stop Server"
			},
			{
				"command": "mai-llmproxy.configureClaudeSettings",
				"title": "MAI-LLMProxy: Configure Claude Code Settings"
			},
			{
				"command": "mai-llmproxy.showClaudeSettings",
				"title": "MAI-LLMProxy: Show Claude Code Settings"
			},
			{
				"command": "mai-llmproxy.removeClaudeSettings",
				"title": "MAI-LLMProxy: Remove Claude Code Settings"
			},
			{
				"command": "mai-llmproxy.configureCodexSettings",
				"title": "MAI-LLMProxy: Configure Codex Settings"
			},
			{
				"command": "mai-llmproxy.showCodexSettings",
				"title": "MAI-LLMProxy: Show Codex Settings"
			},
			{
				"command": "mai-llmproxy.removeCodexSettings",
				"title": "MAI-LLMProxy: Remove Codex Settings"
			},
			{
				"command": "mai-llmproxy.resetGitHubCopilotAuth",
				"title": "MAI-LLMProxy: Reset GitHub Copilot Authentication"
			},
			{
				"command": "mai-llmproxy.checkGithubAuthStatus",
				"title": "MAI-LLMProxy: Check GitHub Copilot Auth Status"
			},
			{
				"command": "mai-llmproxy.killPort",
				"title": "MAI-LLMProxy: Kill Process on Configured Port"
			}
		],
		"configuration": {
			"type": "object",
			"title": "LLM Proxy Configuration",
			"properties": {
				"mai-llmproxy.provider": {
					"type": "string",
					"enum": [
						"litellm",
						"vscode-lm",
						"papyrus"
					],
					"default": "litellm",
					"description": "Choose LLM provider",
					"enumDescriptions": [
						"LiteLLM with GitHub Copilot backend (recommended, requires Python 3.8+)",
						"VS Code Language Model API (fallback, no Python required)",
						"Azure Papyrus Service"
					]
				},
				"mai-llmproxy.serverPort": {
					"type": "number",
					"default": 5000,
					"description": "Port for the proxy server"
				},
				"mai-llmproxy.pythonPath": {
					"type": "string",
					"default": "",
					"description": "Path to Python executable (auto-detected if empty)"
				},
				"mai-llmproxy.claudeAutocompactPct": {
					"type": "number",
					"default": 60,
					"description": "Claude Code autocompact percentage threshold (CLAUDE_AUTOCOMPACT_PCT_OVERRIDE). Provides headroom for the model provider's lower-than-expected context limits."
				},
				"mai-llmproxy.litellmDebug": {
					"type": "boolean",
					"default": false,
					"description": "Enable LiteLLM debug logging"
				}
			}
		}
	},
	"scripts": {
		"build": "npm run compile",
		"build:llm-proxy": "cd ../../llm-proxy && npm install && npm run build",
		"precompile": "npm run build:llm-proxy",
		"dev:compile": "npm run build:llm-proxy && cross-env NODE_ENV=development webpack --mode development",
		"compile": "cross-env NODE_ENV=production webpack --mode production",
		"watch": "webpack --watch",
		"prepackage": "npm run compile",
		"package": "vsce package --allow-star-activation -o "
	},
	"devDependencies": {
		"@aws-sdk/client-s3": "^3.305.0",
		"@mai-engsys/llm-proxy": "file:../../llm-proxy",
		"@types/express": "^5.0.1",
		"@types/mocha": "^10.0.10",
		"@types/node": "20.x",
		"@types/vscode": "^1.98.0",
		"@vscode/test-cli": "^0.0.10",
		"@vscode/test-electron": "^2.4.1",
		"@vscode/vsce": "^3.3.2",
		"axios": "^1.13.5",
		"copy-webpack-plugin": "^13.0.0",
		"cross-env": "^7.0.3",
		"tar": "^7.5.11",
		"terser-webpack-plugin": "^5.3.14",
		"ts-loader": "^9.5.2",
		"typescript": "^5.8.2",
		"unzipper": "^0.12.3",
		"webpack": "^5.98.0",
		"webpack-cli": "^6.0.1"
	},
