namespace CodexLib
{
    using System;
    using System.Collections.Generic;
    using System.Linq;
    using System.Linq.Expressions;
    using System.Threading.Tasks;
    using Azure.ResourceManager;
    using Azure.ResourceManager.MachineLearning;
    using Azure.ResourceManager.Resources;
    using CodexLib.AADAuthProvider;
    using CodexLib.Common;
    using ICodexLib;
    using ICodexLib.Model;

    /// <summary>
    /// EndPointUtil.
    /// </summary>
    public class EndPointUtil : IEndPointUtil
    {
        /// <summary>
        /// aadAuthProvider.
        /// </summary>
        private BaseAADAuthProvider aadAuthProvider;

        /// <summary>
        /// Initializes a new instance of the <see cref="EndPointUtil"/> class.
        /// </summary>
        public EndPointUtil()
        {
        }

        /// <summary>
        /// Initializes a new instance of the <see cref="EndPointUtil"/> class.
        /// </summary>
        /// <param name="aadAuthProvider">aadAuthProvider.</param>
        public EndPointUtil(BaseAADAuthProvider aadAuthProvider)
        {
            this.aadAuthProvider = aadAuthProvider;
        }

        /// <summary>
        /// GetEndPointInfosAsync.
        /// </summary>
        /// <param name="subscriptionID">subscriptionID.</param>
        /// <param name="resourceGroups">resourceGroups.</param>
        /// <param name="endPoints">endPoints.</param>
        /// <param name="skuName">skuName.</param>
        /// <param name="gpuFactor">gpuFactor.</param>
        /// <returns>task of endpoint info.</returns>
        public Task<IEnumerable<EndPointInfo>> GetEndPointInfosAsync(string subscriptionID, IList<string> resourceGroups, IList<string> endPoints, string skuName, int gpuFactor = 8)
        {
            return Task.Run(() => this.GetEndPointInfos(subscriptionID, resourceGroups, endPoints, skuName, gpuFactor));
        }

        /// <summary>
        /// GetDeploymentInfos.
        /// </summary>
        /// <param name="subscriptionID">subscriptionID.</param>
        /// <param name="resourceGroup">resourceGroup.</param>
        /// <param name="workSpace">workSpace.</param>
        /// <param name="endPoint">endPoint.</param>
        /// <returns>task of deployment info.</returns>
        public IEnumerable<DeploymentInfo> GetDeploymentInfos(string subscriptionID, string resourceGroup, string workSpace, string endPoint)
        {
            IList<DeploymentInfo> res = new List<DeploymentInfo>();
            var (_, _, _, onlineEndPoint) = AzureMachineLearningHelper.GetMachineLearningResource(this.aadAuthProvider, subscriptionID, resourceGroup, workSpace, endPoint);
            var deploymentResources = onlineEndPoint.GetMachineLearningOnlineDeployments().GetAll().ToList();
            foreach (var deployment in deploymentResources)
            {
                res.Add(this.CreateDeploymentInfo(deployment.Data.Name, deployment.Data.Sku.Capacity ?? 0, deployment.Data.Properties.InstanceType, deployment.Data.Properties.Properties));
            }

            return res;
        }

        /// <summary>
        /// GetEndPointInfos.
        /// </summary>
        /// <param name="subscriptionID">subscriptionID.</param>
        /// <param name="resourceGroups">resourceGroups.</param>
        /// <param name="endPoints">endPoints.</param>
        /// <param name="skuName">skuName.</param>
        /// <param name="gpuFactor">gpuFactor.</param>
        /// <returns>infos.</returns>
        private IEnumerable<EndPointInfo> GetEndPointInfos(string subscriptionID, IList<string> resourceGroups, IList<string> endPoints, string skuName, int gpuFactor = 8)
        {
            IList<EndPointInfo> endpointInfos = new List<EndPointInfo>();

            ArmClient client = new ArmClient(this.aadAuthProvider.GetTokenCredential());
            var subscription = client.GetSubscriptions().GetAsync(subscriptionID).Result.Value;
            ResourceGroupCollection resourceGroupCollection = subscription.GetResourceGroups();

            for (int i = 0; i < resourceGroups.Count; i++)
            {
                ResourceGroupResource resourceGroup = resourceGroupCollection.GetAsync(resourceGroups[i]).Result;
                var workspaceResourceList = resourceGroup.GetMachineLearningWorkspaces().GetAll().ToList();
                foreach (var workspaceResource in workspaceResourceList)
                {
                    string workspaceName = workspaceResource.Data.Name;
                    var onlineEndpoints = workspaceResource.GetMachineLearningOnlineEndpoints().GetAll().ToList();

                    foreach (var onlineEndPoint in onlineEndpoints)
                    {
                        if (endPoints.Contains(onlineEndPoint.Data.Name))
                        {
                            var depolymentResources = onlineEndPoint.GetMachineLearningOnlineDeployments().GetAll().ToList();
                            int modelCount = 0;
                            int gpuCount = 0;
                            var isLowPriority = false;
                            foreach (var d in depolymentResources)
                            {
                                if (!string.Equals(d.Data.Properties.ProvisioningState.ToString(), "Succeeded", StringComparison.OrdinalIgnoreCase))
                                {
                                    continue;
                                }

                                var deploymentInfo = this.CreateDeploymentInfo(d.Data.Name, d.Data.Sku.Capacity ?? 0, d.Data.Properties.InstanceType, d.Data.Properties.Properties);
                                modelCount += deploymentInfo.InstanceCount;
                                gpuCount += deploymentInfo.UsedGPUCount;
                                isLowPriority = deploymentInfo.IsLowPriority;
                            }

                            endpointInfos.Add(new EndPointInfo(onlineEndPoint.Data.Location.ToString(), onlineEndPoint.Data.Name, modelCount, gpuCount, skuName, subscriptionID, resourceGroups[i], workspaceName, isLowPriority));
                        }
                    }
                }
            }

            return endpointInfos;
        }

        /// <summary>
        /// GetEndPointInfos.
        /// </summary>
        /// <param name="subscriptionID">subscriptionID.</param>
        /// <param name="resourceGroups">resourceGroups.</param>
        /// <param name="workSpaces">workSpaces.</param>
        /// <returns>infos.</returns>
        private IList<MachineLearningOnlineEndpointResource> GetMachineLearningOnlineEndpoints(string subscriptionID, IList<string> resourceGroups, IList<string> workSpaces)
        {
            ArmClient client = new ArmClient(this.aadAuthProvider.GetTokenCredential());
            var subscription = client.GetSubscriptions().GetAsync(subscriptionID).Result.Value;
            ResourceGroupCollection resourceGroupCollection = subscription.GetResourceGroups();
            List<MachineLearningOnlineEndpointResource> onlineEndpoints = new List<MachineLearningOnlineEndpointResource>();
            for (int i = 0; i < resourceGroups.Count; i++)
            {
                ResourceGroupResource resourceGroup = resourceGroupCollection.GetAsync(resourceGroups[i]).Result;
                for (int j = 0; j < workSpaces.Count; j++)
                {
                    MachineLearningWorkspaceResource workspaceResource = resourceGroup.GetMachineLearningWorkspace(workSpaces[j]).Value;
                    onlineEndpoints.AddRange(workspaceResource.GetMachineLearningOnlineEndpoints().GetAll().ToList());
                }
            }

            return onlineEndpoints;
        }

        /// <summary>
        /// CreateDeploymentInfo.
        /// </summary>
        /// <param name="deploymentName">deploymentName.</param>
        /// <param name="instanceCount">instanceCount.</param>
        /// <param name="instanceType">instanceType.</param>
        /// <param name="propertiesDic">propertiesDic.</param>
        /// <returns>deployment info.</returns>
        private DeploymentInfo CreateDeploymentInfo(string deploymentName, int instanceCount, string instanceType, IDictionary<string, string> propertiesDic)
        {
            int nodePerInstance = this.GetNodeCountPerInstance(propertiesDic);
            bool isLowPriority = this.ContainsLowPriority(propertiesDic);
            string sku = Utility.GetSKUName(instanceType);
            int usedGPUCount = instanceCount * nodePerInstance * Utility.GetGPUCount(sku, isLowPriority);
            return new DeploymentInfo(deploymentName, instanceCount, instanceType, nodePerInstance, isLowPriority, usedGPUCount);
        }

        /// <summary>
        /// GetNodeCountPerInstance.
        /// </summary>
        /// <param name="propertiesDic">propertiesDic.</param>
        /// <returns>int.</returns>
        private int GetNodeCountPerInstance(IDictionary<string, string> propertiesDic)
        {
            if (propertiesDic == null)
            {
                return 1;
            }

            const string NodeGroupEnablePropertyName = "NODE_GROUP_ENABLED";
            const string NodeGroupSizePropertyName = "MIR_NODE_GROUP_SIZE";
            if (!(propertiesDic?.ContainsKey(NodeGroupEnablePropertyName) ?? false))
            {
                return 1;
            }

            if (!(propertiesDic?.ContainsKey(NodeGroupSizePropertyName) ?? false))
            {
                return 1;
            }

            if (!bool.TryParse(propertiesDic[NodeGroupEnablePropertyName], out bool isNodeGroupEnabled) || !isNodeGroupEnabled)
            {
                return 1;
            }

            if (!int.TryParse(propertiesDic[NodeGroupSizePropertyName], out int nodeCount))
            {
                return 1;
            }

            return nodeCount;
        }

        /// <summary>
        /// GetNodeCountPerInstance.
        /// </summary>
        /// <param name="propertiesDic">propertiesDic.</param>
        /// <returns>int.</returns>
        private bool ContainsLowPriority(IDictionary<string, string> propertiesDic)
        {
            if (propertiesDic == null)
            {
                return false;
            }

            const string LowPriorityPropertyName = "AML_MOE_USE_VM_LOW_PRIORITY";

            if (!(propertiesDic?.ContainsKey(LowPriorityPropertyName) ?? false))
            {
                return false;
            }

            if (!bool.TryParse(propertiesDic[LowPriorityPropertyName], out bool returnValue))
            {
                return false;
            }

            return returnValue;
        }
    }
}

