// --------------------------------------------------------------------
// <copyright file="JsonSerializerExt.cs" company="Microsoft">
// Copyright (c) Microsoft Corporation.
// </copyright>
// --------------------------------------------------------------------
namespace CodexLib.Common
{
    using System;
    using System.Reflection;
    using System.Text.Json;

    /// <summary>
    /// JsonSerializerExt.
    /// </summary>.
    internal class JsonSerializerExt
    {
        /// <summary>
        /// RawJsonContentPropertyName.
        /// </summary>
        private const string RawJsonContentPropertyName = "RawJsonContent";

        /// <summary>
        /// Deserialize with Raw Json Content.
        /// </summary>
        /// <typeparam name="T">T.</typeparam>
        /// <param name="jsonContent">jsonContent.</param>
        /// <returns>obj.</returns>
        public static T DeserializeWithRawJsonContent<T>(string jsonContent)
        {
            var obj = JsonSerializer.Deserialize<T>(jsonContent);
            var rawJsonContentProperty = GetInnerRawContentProperty(typeof(T));
            if (rawJsonContentProperty != null)
            {
                rawJsonContentProperty.SetValue(obj, jsonContent);
            }

            return obj;
        }

        /// <summary>
        /// GetInnerRawContentProperty.
        /// </summary>
        /// <param name="type">type.</param>
        /// <returns>property info.</returns>
        private static PropertyInfo GetInnerRawContentProperty(Type type)
        {
            var property = type.GetProperty(RawJsonContentPropertyName, System.Reflection.BindingFlags.SetProperty | System.Reflection.BindingFlags.GetProperty | System.Reflection.BindingFlags.Public | System.Reflection.BindingFlags.Instance);
            if (property != null && property.PropertyType == typeof(string))
            {
                return property;
            }

            return null;
        }
    }
}

