 14→    /// Each method is idempotent and can be composed in a pipeline.
 15→    /// </summary>
 16→    public static partial class InputSanitizer
 17→    {
 18→        /// <summary>
 19→        /// Sanitizes a URL by stripping invisible/whitespace Unicode characters
 20→        /// and validating that only ASCII characters remain.
 21→        /// Returns a <see cref="SanitizeResult"/> indicating success or failure
 22→        /// with details about what was changed or rejected.
 23→        /// </summary>
 24→        /// <param name="url">The raw URL string from user input.</param>
 25→        /// <returns>A result containing the sanitized URL or an error message.</returns>
 26→        public static SanitizeResult SanitizeUrl(string url)
 27→        {
