// --------------------------------------------------------------------
// <copyright file="InputSanitizer.cs" company="Microsoft">
//   Copyright (c) Microsoft. All rights reserved.
// </copyright>
// --------------------------------------------------------------------
namespace CodexCore.Util
{
    using System.Text;
    using System.Text.RegularExpressions;

    /// <summary>
    /// Provides extensible input sanitization for user-supplied values before
    /// they are persisted into configuration files or submitted in PRs.
    /// Each method is idempotent and can be composed in a pipeline.
    /// </summary>
    public static partial class InputSanitizer
    {
        /// <summary>
        /// Sanitizes a URL by stripping invisible/whitespace Unicode characters
        /// and validating that only ASCII characters remain.
        /// Returns a <see cref="SanitizeResult"/> indicating success or failure
        /// with details about what was changed or rejected.
        /// </summary>
        /// <param name="url">The raw URL string from user input.</param>
        /// <returns>A result containing the sanitized URL or an error message.</returns>
        public static SanitizeResult SanitizeUrl(string url)
        {
            if (string.IsNullOrWhiteSpace(url))
            {
                return SanitizeResult.Fail("URL cannot be null or empty.");
            }

            var original = url;

            // Step 1: Strip all Unicode whitespace and control characters.
            // This covers U+202F (narrow no-break space), U+00A0 (NBSP),
            // U+200B (zero-width space), U+FEFF (BOM), and all others
            // in the Unicode "separator" and "format" categories.
            url = StripInvisibleCharacters(url);

            // Step 2: Trim leading/trailing ASCII whitespace.
            url = url.Trim();

            if (string.IsNullOrEmpty(url))
            {
                return SanitizeResult.Fail("URL is empty after removing invisible characters.");
            }

            // Step 3: Reject any remaining non-ASCII characters.
            // Valid URLs are ASCII-only per RFC 3986; internationalized
            // domain names must be Punycode-encoded before use.
            if (!IsAsciiOnly(url))
            {
                var nonAscii = GetNonAsciiDetails(url);
                return SanitizeResult.Fail(
                    $"URL contains non-ASCII characters that are not allowed: {nonAscii}. " +
                    "Ensure the URL uses only ASCII characters. " +
                    "Internationalized domain names must use Punycode encoding.");
            }

            // Step 4: Basic structural validation.
            if (!url.StartsWith("https://", StringComparison.OrdinalIgnoreCase) &&
                !url.StartsWith("http://", StringComparison.OrdinalIgnoreCase))
            {
                return SanitizeResult.Fail("URL must start with http:// or https://.");
            }

            var wasModified = !string.Equals(original, url, StringComparison.Ordinal);
            return SanitizeResult.Ok(url, wasModified);
        }

        /// <summary>
        /// Strips Unicode characters that are invisible or act as whitespace,
        /// including: format characters (Cf), separator characters (Zs, Zl, Zp),
        /// and specific control characters commonly injected via copy-paste.
        /// </summary>
        /// <param name="input">The input string.</param>
        /// <returns>The string with invisible characters removed.</returns>
        public static string StripInvisibleCharacters(string input)
        {
            if (string.IsNullOrEmpty(input))
            {
                return input;
            }

            var sb = new StringBuilder(input.Length);
            foreach (var c in input)
            {
                // Preserve ASCII space (U+0020) — it falls under SpaceSeparator
                // but is a normal character that later validation can handle.
                if (c == ' ')
                {
                    sb.Append(c);
                    continue;
                }

                var category = char.GetUnicodeCategory(c);
                switch (category)
                {
                    // Unicode whitespace/separator categories
                    case System.Globalization.UnicodeCategory.SpaceSeparator:     // Zs: NBSP, NNBSP, etc.
                    case System.Globalization.UnicodeCategory.LineSeparator:      // Zl: U+2028
                    case System.Globalization.UnicodeCategory.ParagraphSeparator: // Zp: U+2029
                    case System.Globalization.UnicodeCategory.Format:             // Cf: ZWJ, ZWNJ, BOM, etc.
                        // Skip these characters — they are invisible/whitespace
                        break;

                    default:
                        sb.Append(c);
                        break;
                }
            }

            return sb.ToString();
        }

        /// <summary>
        /// Returns true if the string contains only ASCII characters (U+0000–U+007F).
        /// </summary>
        private static bool IsAsciiOnly(string input)
        {
            foreach (var c in input)
            {
                if (c > 127)
                {
                    return false;
                }
            }

            return true;
        }

        /// <summary>
        /// Returns a human-readable description of non-ASCII characters found in the input,
        /// showing their Unicode code points and positions.
        /// </summary>
        private static string GetNonAsciiDetails(string input)
        {
            var details = new List<string>();
            for (int i = 0; i < input.Length && details.Count < 5; i++)
            {
                if (input[i] > 127)
                {
                    details.Add($"U+{(int)input[i]:X4} at position {i}");
                }
            }

            return string.Join(", ", details);
        }
    }

    /// <summary>
    /// Represents the result of a sanitization operation.
    /// </summary>
    public sealed class SanitizeResult
    {
        private SanitizeResult(bool success, string value, string errorMessage, bool wasModified)
        {
            this.Success = success;
            this.Value = value;
            this.ErrorMessage = errorMessage;
            this.WasModified = wasModified;
        }

        /// <summary>
        /// Gets a value indicating whether sanitization succeeded.
        /// </summary>
        public bool Success { get; }

        /// <summary>
        /// Gets the sanitized value. Null when <see cref="Success"/> is false.
        /// </summary>
        public string Value { get; }

        /// <summary>
        /// Gets the error message. Null when <see cref="Success"/> is true.
        /// </summary>
        public string ErrorMessage { get; }

        /// <summary>
        /// Gets a value indicating whether the input was modified during sanitization.
        /// Useful for logging/auditing when invisible characters were silently stripped.
        /// </summary>
        public bool WasModified { get; }

        /// <summary>
        /// Creates a successful result.
        /// </summary>
        public static SanitizeResult Ok(string sanitizedValue, bool wasModified = false)
            => new SanitizeResult(true, sanitizedValue, null, wasModified);

        /// <summary>
        /// Creates a failed result with an error message.
        /// </summary>
        public static SanitizeResult Fail(string errorMessage)
            => new SanitizeResult(false, null, errorMessage, false);
    }
}

