        public void SanitizeUrl_OnlyInvisibleChars_Fails()
        {
            var result = InputSanitizer.SanitizeUrl("\u202F\u200B\u00A0");
            Assert.IsFalse(result.Success);
        }

        [TestMethod]
        public void SanitizeUrl_MissingScheme_Fails()
        {
            var result = InputSanitizer.SanitizeUrl("example.com/path");
            Assert.IsFalse(result.Success);
            Assert.IsTrue(result.ErrorMessage.Contains("http"));
        }

        [TestMethod]
        public void SanitizeUrl_LeadingTrailingWhitespace_Trimmed()
        {
            var url = "  https://example.com/path  ";
            var result = InputSanitizer.SanitizeUrl(url);
            Assert.IsTrue(result.Success);
            Assert.AreEqual("https://example.com/path", result.Value);
            Assert.IsTrue(result.WasModified);
        }

        [TestMethod]
        public void SanitizeUrl_HttpUrl_Accepted()
        {
            var url = "http://internal.bing.prod.dlis.binginternal.com:86/route/some-service";
            var result = InputSanitizer.SanitizeUrl(url);
            Assert.IsTrue(result.Success);
            Assert.AreEqual(url, result.Value);
        }

        [TestMethod]
        public void StripInvisibleCharacters_PreservesAsciiSpace()
        {
            var input = "hello world";
            var result = InputSanitizer.StripInvisibleCharacters(input);
            Assert.AreEqual("hello world", result);
        }

        [TestMethod]
        public void StripInvisibleCharacters_NullInput_ReturnsNull()
        {
            Assert.IsNull(InputSanitizer.StripInvisibleCharacters(null));
        }

        [TestMethod]
        public void StripInvisibleCharacters_EmptyInput_ReturnsEmpty()
        {
            Assert.AreEqual(string.Empty, InputSanitizer.StripInvisibleCharacters(string.Empty));
        }

        [TestMethod]
        public void SanitizeUrl_LineSeparator_IsStripped()
        {
            // U+2028 (line separator)
            var url = "https://example.com/path\u2028value";
            var result = InputSanitizer.SanitizeUrl(url);
            Assert.IsTrue(result.Success);
            Assert.AreEqual("https://example.com/pathvalue", result.Value);
        }

        [TestMethod]
        public void SanitizeUrl_RightToLeftMark_IsStripped()
        {
            // U+200F (right-to-left mark) - format character
            var url = "https://example.com/path\u200Fvalue";
            var result = InputSanitizer.SanitizeUrl(url);
            Assert.IsTrue(result.Success);
            Assert.AreEqual("https://example.com/pathvalue", result.Value);
        }
    }
}

