 17→    /// <summary>
 18→    /// Data transfer object for Papyrus Control configuration file.
 19→    /// </summary>
 20→    public class PapyrusControlConfigJsonCollection
 21→    {
 22→        private static readonly JsonSerializerOptions IgnoreNullJsonOptions = new()
 23→        {
 24→            DefaultIgnoreCondition = JsonIgnoreCondition.WhenWritingNull,
 25→        };
 26→
 27→        /// <summary>
 28→        /// Gets the path to the folder which contains all the single model config files.
 29→        /// </summary>
 30→        public required string SingleModelConfigFolderPath { get; init; }
 31→
 32→        /// <summary>
 33→        /// Gets the dictionary mapping file paths to corresponding JsonObjects.
 34→        /// </summary>
 35→        public required IDictionary<string, JsonObject> SingleModelConfigJsons { get; init; }
 36→
 37→        /// <summary>
 38→        /// Gets the model traffic group configuration JSON object.
 39→        /// </summary>
 40→        /// <param name="modelName">Model Name.</param>
 41→        /// <param name="trafficGroup">Traffic Group.</param>
 42→        /// <returns>Model Traffic Config JSON object.</returns>
 43→        public JsonObject GetModelTrafficGroupConfigJson(string modelName, string trafficGroup)
 44→        {
 45→            var config = this.GetModelTrafficGroupConfigJsonHelper(modelName, trafficGroup);
 46→
 47→            // Validate whether there are any config rows present across the top-level and one-model configs
 48→            if (config == null)
 49→            {
 50→                throw new UserException($"Unable to find specified traffic group - ModelName: {modelName}, TrafficGroup: {trafficGroup}");
 51→            }
 52→
 53→            return config;
 54→        }
 55→
 56→        /// <summary>
 57→        /// Retrieves the configuration hash for the specified model and traffic group.
 58→        /// </summary>
 59→        /// <param name="modelName">The name of the model for which to obtain the configuration hash. Cannot be null or empty.</param>
 60→        /// <param name="trafficGroup">The name of the traffic group associated with the model. Cannot be null or empty.</param>
 61→        /// <returns>A string containing the configuration hash for the specified model and traffic group.</returns>
 62→        public string GetModelTrafficGroupConfigHash(string modelName, string trafficGroup)
 63→        {
 64→            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
 65→            return config.ContainsKey("Hash") ? config["Hash"].GetValue<string>() : string.Empty;
 66→        }
 67→
 68→        /// <summary>
 69→        /// Creates a new application quota for a specific model and traffic group.
 70→        /// </summary>
 71→        /// <param name="modelName">Model Name.</param>
 72→        /// <param name="trafficGroup">Traffic Group.</param>
 73→        /// <param name="appIdQuota">Application ID Quota.</param>
 74→        /// <param name="commandContext">Command Context.</param>
 75→        public void CreateAppQuota(string modelName, string trafficGroup, AppIdQuota appIdQuota, CommandContext commandContext)
 76→        {
 77→            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
 78→            var appQuotas = config["ConfigData"]["AppIdQuotaConfigs"].AsArray();
 79→
 80→            var normalizedAppQuotaConfig = appIdQuota with
 81→            {
 82→                AppId = appIdQuota.AppId?.ToLowerInvariant(),
 83→            };
 84→
 85→            // Validate the input.
 86→            if (appIdQuota == null)
 87→            {
 88→                throw new UserException("AppIdQuota cannot be null");
 89→            }
 90→            else if (string.IsNullOrWhiteSpace(appIdQuota.AppId))
 91→            {
 92→                throw new UserException("AppId in AppIdQuota cannot be null or empty");
 93→            }
 94→            else if (appQuotas.Where(s => s["AppId"].GetValue<string>() == normalizedAppQuotaConfig.AppId).Any())
 95→            {
 96→                throw new UserException($"AppIdQuota with AppId {normalizedAppQuotaConfig.AppId} already exists");
 97→            }
 98→
 99→            appQuotas.Add(JsonSerializer.SerializeToNode(normalizedAppQuotaConfig, IgnoreNullJsonOptions));
100→
101→            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);
102→
103→            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
104→            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
105→        }
106→
107→        /// <summary>
108→        /// Deletes the application quota entry for the specified application ID from the configuration associated with
109→        /// the given model and traffic group.
110→        /// </summary>
111→        /// <param name="modelName">The name of the model whose configuration contains the application quota to delete.</param>
112→        /// <param name="trafficGroup">The name of the traffic group within the model configuration.</param>
113→        /// <param name="appIdQuota">The application ID identifying the quota entry to remove.</param>
114→        /// <param name="commandContext">Command Context.</param>
115→        public void DeleteAppQuota(string modelName, string trafficGroup, AppIdQuota appIdQuota, CommandContext commandContext)
116→        {
117→            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
118→            var appQuotas = config["ConfigData"]["AppIdQuotaConfigs"].AsArray();
119→            var foundAppQuota = appQuotas.Where(s => s["AppId"].GetValue<string>() == appIdQuota.AppId).FirstOrDefault();
120→            if (foundAppQuota == null)
121→            {
122→                throw new UserException($"AppQuota with AppId '{appIdQuota.AppId}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}' was not found in config config");
123→            }
124→
125→            appQuotas.Remove(foundAppQuota);
126→
127→            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);
128→
129→            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
130→            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
131→        }
132→
133→        /// <summary>
134→        /// Updates an existing application quota in the configuration for the specified model and traffic group.
135→        /// </summary>
136→        /// <param name="modelName">Model Name</param>
137→        /// <param name="trafficGroup">Traffic Group</param>
138→        /// <param name="appIdQuota">Application ID Quota</param>
139→        /// <param name="commandContext">Command Context</param>
140→        public void UpdateAppQuota(string modelName, string trafficGroup, AppIdQuota appIdQuota, CommandContext commandContext)
141→        {
142→            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
143→            var appQuotas = config["ConfigData"]["AppIdQuotaConfigs"].AsArray();
144→            var foundAppQuota = appQuotas.Where(s => s["AppId"].GetValue<string>() == appIdQuota.AppId).FirstOrDefault();
145→            if (foundAppQuota == null)
146→            {
147→                throw new UserException($"AppQuota with AppId '{appIdQuota.AppId}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}' was not found in config config");
148→            }
149→
150→            var parsedFoundAppQuota = JsonSerializer.Deserialize<AppIdQuota>(foundAppQuota.ToJsonString());
151→            if (parsedFoundAppQuota == appIdQuota)
152→            {
153→                throw new UserException($"Attempting to update AppQuota with same exact values, AppId '{appIdQuota.AppId}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}'");
154→            }
155→
156→            var patchAppQuotaObject = JsonSerializer.SerializeToNode(appIdQuota, IgnoreNullJsonOptions).AsObject();
157→            var mergedAppQuotaObject = foundAppQuota.AsObject().Merge(patchAppQuotaObject);
158→            if (appIdQuota.CapacityRatioNotSubjectToBorrowing == null
159→                && mergedAppQuotaObject.ContainsKey("CapacityRatioNotSubjectToBorrowing"))
160→            {
161→                mergedAppQuotaObject.Remove("CapacityRatioNotSubjectToBorrowing");
162→            }
163→
164→            foundAppQuota.ReplaceWith(mergedAppQuotaObject);
165→
166→            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);
167→
168→            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
169→            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
170→        }
171→
172→        /// <summary>
173→        /// Creates a new endpoint for a specific model and traffic group.
174→        /// </summary>
175→        /// <param name="modelName">Model name</param>
176→        /// <param name="trafficGroup">Traffic group</param>
177→        /// <param name="endpoint">Endpoint to create</param>
178→        /// <param name="commandContext">Command Context</param>
179→        public void CreateEndpoint(string modelName, string trafficGroup, Endpoint endpoint, CommandContext commandContext)
180→        {
181→            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
182→            var endpoints = config["ConfigData"]["EndpointConfigs"].AsArray();
183→
184→            // Validate the input.
185→            if (endpoint == null)
186→            {
187→                throw new UserException("Endpoint cannot be null");
188→            }
189→
190→            // Sanitize URL: strip invisible Unicode characters and validate ASCII-only.
191→            var urlResult = CodexCore.Util.InputSanitizer.SanitizeUrl(endpoint.URL);
192→            if (!urlResult.Success)
193→            {
194→                throw new UserException($"Invalid endpoint URL: {urlResult.ErrorMessage}");
195→            }
196→
197→            endpoint.URL = urlResult.Value;
198→
199→            if (string.IsNullOrWhiteSpace(endpoint.URL))
200→            {
201→                throw new UserException("URL in Endpoint cannot be null or empty");
202→            }
203→            else if (endpoints.Where(s => s["URL"].GetValue<string>() == endpoint.URL).Any())
204→            {
205→                throw new UserException($"Endpoint with URL {endpoint.URL} already exists");
206→            }
207→            else if (endpoint.GlobalId != 0)
208→            {
209→                throw new UserException("GlobalId in Endpoint must be 0 for new endpoints");
210→            }
211→
212→            int maxGlobalId = endpoints.Any() ? endpoints.Max(s => s["GlobalId"].GetValue<int>()) : 0;
213→            endpoint.GlobalId = maxGlobalId + 1;
214→
215→            endpoints.Add(JsonSerializer.SerializeToNode(endpoint, IgnoreNullJsonOptions));
216→
217→            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);
218→
219→            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
220→            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
221→        }
222→
223→        /// <summary>
224→        /// Deletes the endpoint entry for the specified endpoint from the configuration associated with
225→        /// the given model name and traffic group.
226→        /// </summary>
227→        /// <param name="modelName">Model name.</param>
228→        /// <param name="trafficGroup">Traffic group.</param>
229→        /// <param name="endpoint">Endpoint to delete.</param>
230→        /// <param name="commandContext">Command Context.</param>
231→        public void DeleteEndpoint(string modelName, string trafficGroup, Endpoint endpoint, CommandContext commandContext)
232→        {
233→            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
234→            var endpoints = config["ConfigData"]["EndpointConfigs"].AsArray();
235→            var foundEp = endpoints
236→                    .Where(s => s["GlobalId"].GetValue<int>() == endpoint.GlobalId && s["URL"].GetValue<string>() == endpoint.URL)
237→                    .FirstOrDefault();
238→            if (foundEp == null)
239→            {
240→                throw new UserException($"Endpoint: GlobalId: '{endpoint.GlobalId}' URL: '{endpoint.URL}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}' was not found in config config");
241→            }
242→
243→            endpoints.Remove(foundEp);
244→
245→            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);
246→
247→            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
248→            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
249→        }
250→
251→        /// <summary>
252→        /// Updates an existing endpoint in the configuration for the specified model and traffic group.
253→        /// </summary>
254→        /// <param name="modelName">Model Name.</param>
255→        /// <param name="trafficGroup">Traffic Group.</param>
256→        /// <param name="endpoint">Endpoint to update.</param>
257→        /// <param name="commandContext">Command Context.</param>
258→        public void UpdateEndpoint(string modelName, string trafficGroup, Endpoint endpoint, CommandContext commandContext)
259→        {
260→            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
261→            var endpoints = config["ConfigData"]["EndpointConfigs"].AsArray();
262→            var foundEp = endpoints
263→                    .Where(s => s["GlobalId"].GetValue<int>() == endpoint.GlobalId)
264→                    .FirstOrDefault();
265→            if (foundEp == null)
266→            {
267→                throw new UserException($"Endpoint with GlobalId '{endpoint.GlobalId}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}' was not found in config config");
268→            }
269→
270→            var parsedFoundEp = JsonSerializer.Deserialize<Endpoint>(foundEp.ToJsonString());
271→            if (parsedFoundEp == endpoint)
272→            {
273→                throw new UserException($"Attempting to update Endpoint with same exact values, GlobalId '{endpoint.GlobalId}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}'");
274→            }
275→
276→            var patchEQObject = JsonSerializer.SerializeToNode(endpoint, IgnoreNullJsonOptions).AsObject();
277→            var mergedObject = foundEp.AsObject().Merge(patchEQObject);
278→            if (endpoint.MaxConcurrencyPerInstance == null
279→                && mergedObject.ContainsKey("MaxConcurrencyPerInstance"))
280→            {
281→                mergedObject.Remove("MaxConcurrencyPerInstance");
282→            }
283→
284→            if (endpoint.SafeConcurrencyPerInstance == null
285→                && mergedObject.ContainsKey("SafeConcurrencyPerInstance"))
286→            {
287→                mergedObject.Remove("SafeConcurrencyPerInstance");
288→            }
289→
290→            foundEp.ReplaceWith(mergedObject);
291→            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);
292→
293→            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
294→            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
295→        }
296→
297→        /// <summary>
298→        /// Create a new ModelTrafficGroupConfig entry in the Papyrus Control configuration.
299→        /// </summary>
300→        /// <param name="modelName">Model name.</param>
301→        /// <param name="trafficGroup">Traffic group.</param>
302→        /// <param name="modelTrafficGroupDetails">Model traffic group details.</param>
303→        /// <param name="glbName">GLB name (Needed to create the path name).</param>
304→        /// <param name="commandContext">Command Context.</param>
305→        public void CreateModelTrafficGroup(string modelName, string trafficGroup, ModelTrafficGroupDetails modelTrafficGroupDetails, string glbName, CommandContext commandContext)
306→        {
307→            if (this.GetModelTrafficGroupConfigJsonHelper(modelName, trafficGroup)?.Any() == true)
308→            {
309→                throw new UserException($"ModelTrafficGroup with ModelName '{modelName}' & TrafficGroup '{trafficGroup}' already exists in config config");
310→            }
311→
312→            var configData = new ModelTrafficGroupConfigData
313→            {
314→                EndpointConfigs = [],
315→                AppIdQuotaConfigs = [],
316→                ModelConfigDetails = modelTrafficGroupDetails,
317→            };
318→            var modelNameTrafficGroupRow = new ModelTrafficGroupConfig
319→            {
320→                ModelTrafficGroup = new ModelTrafficGroup { ModelName = modelName, TrafficGroup = trafficGroup },
321→                ConfigData = configData,
322→            };
323→
324→            var node = JsonSerializer.SerializeToNode(modelNameTrafficGroupRow).AsObject();
325→            node["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(node["ConfigData"]);
326→
327→            var filePath = $"{this.SingleModelConfigFolderPath}{glbName}/{modelName}_{trafficGroup}.json";
328→            this.SingleModelConfigJsons[filePath] = new JsonObject
329→            {
330→                ["SkipStaging"] = false, // TODO: Get skip staging value from the user.
331→                ["ModelTrafficGroupConfig"] = node,
332→            };
333→
334→            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
335→            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Add);
336→        }
337→
338→        /// <summary>
339→        /// Deletes the ModelTrafficGroupConfig entry from the Papyrus Control configuration.
340→        /// </summary>
341→        /// <param name="modelName">Model name.</param>
342→        /// <param name="trafficGroup">Traffic group.</param>
343→        /// <param name="commandContext">Command Context.</param>
344→        public void DeleteModelTrafficGroup(string modelName, string trafficGroup, CommandContext commandContext)
345→        {
346→            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
347→            this.SingleModelConfigJsons.Remove(fileChanged);
348→            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Delete);
349→        }
350→
351→        /// <summary>
352→        /// Updates the ModelTrafficGroupDetails for the specified model and traffic group.
353→        /// </summary>
354→        /// <param name="modelName">Model name.</param>
