namespace CodexCore.Models.DTOs.PapyrusConfig
{
    using System.Text.Json;
    using System.Text.Json.Nodes;
    using System.Text.Json.Serialization;
    using CodexCore.Util;
    using GitClient.Interface;
    using Microsoft.Falcon.LibOnePortal;
    using Papyrus.SDK;
    using Papyrus.SDK.DTOs;

    /// <summary>
    /// Data transfer object for Papyrus Control configuration file.
    /// </summary>
    public class PapyrusControlConfigJsonCollection
    {
        private static readonly JsonSerializerOptions IgnoreNullJsonOptions = new()
        {
            DefaultIgnoreCondition = JsonIgnoreCondition.WhenWritingNull,
        };

        /// <summary>
        /// Gets the path to the folder which contains all the single model config files.
        /// </summary>
        public required string SingleModelConfigFolderPath { get; init; }

        /// <summary>
        /// Gets the dictionary mapping file paths to corresponding JsonObjects.
        /// </summary>
        public required IDictionary<string, JsonObject> SingleModelConfigJsons { get; init; }

        /// <summary>
        /// Gets the model traffic group configuration JSON object.
        /// </summary>
        /// <param name="modelName">Model Name.</param>
        /// <param name="trafficGroup">Traffic Group.</param>
        /// <returns>Model Traffic Config JSON object.</returns>
        public JsonObject GetModelTrafficGroupConfigJson(string modelName, string trafficGroup)
        {
            var config = this.GetModelTrafficGroupConfigJsonHelper(modelName, trafficGroup);

            // Validate whether there are any config rows present across the top-level and one-model configs
            if (config == null)
            {
                throw new UserException($"Unable to find specified traffic group - ModelName: {modelName}, TrafficGroup: {trafficGroup}");
            }

            return config;
        }

        /// <summary>
        /// Retrieves the configuration hash for the specified model and traffic group.
        /// </summary>
        /// <param name="modelName">The name of the model for which to obtain the configuration hash. Cannot be null or empty.</param>
        /// <param name="trafficGroup">The name of the traffic group associated with the model. Cannot be null or empty.</param>
        /// <returns>A string containing the configuration hash for the specified model and traffic group.</returns>
        public string GetModelTrafficGroupConfigHash(string modelName, string trafficGroup)
        {
            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
            return config.ContainsKey("Hash") ? config["Hash"].GetValue<string>() : string.Empty;
        }

        /// <summary>
        /// Creates a new application quota for a specific model and traffic group.
        /// </summary>
        /// <param name="modelName">Model Name.</param>
        /// <param name="trafficGroup">Traffic Group.</param>
        /// <param name="appIdQuota">Application ID Quota.</param>
        /// <param name="commandContext">Command Context.</param>
        public void CreateAppQuota(string modelName, string trafficGroup, AppIdQuota appIdQuota, CommandContext commandContext)
        {
            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
            var appQuotas = config["ConfigData"]["AppIdQuotaConfigs"].AsArray();

            var normalizedAppQuotaConfig = appIdQuota with
            {
                AppId = appIdQuota.AppId?.ToLowerInvariant(),
            };

            // Validate the input.
            if (appIdQuota == null)
            {
                throw new UserException("AppIdQuota cannot be null");
            }
            else if (string.IsNullOrWhiteSpace(appIdQuota.AppId))
            {
                throw new UserException("AppId in AppIdQuota cannot be null or empty");
            }
            else if (appQuotas.Where(s => s["AppId"].GetValue<string>() == normalizedAppQuotaConfig.AppId).Any())
            {
                throw new UserException($"AppIdQuota with AppId {normalizedAppQuotaConfig.AppId} already exists");
            }

            appQuotas.Add(JsonSerializer.SerializeToNode(normalizedAppQuotaConfig, IgnoreNullJsonOptions));

            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);

            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
        }

        /// <summary>
        /// Deletes the application quota entry for the specified application ID from the configuration associated with
        /// the given model and traffic group.
        /// </summary>
        /// <param name="modelName">The name of the model whose configuration contains the application quota to delete.</param>
        /// <param name="trafficGroup">The name of the traffic group within the model configuration.</param>
        /// <param name="appIdQuota">The application ID identifying the quota entry to remove.</param>
        /// <param name="commandContext">Command Context.</param>
        public void DeleteAppQuota(string modelName, string trafficGroup, AppIdQuota appIdQuota, CommandContext commandContext)
        {
            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
            var appQuotas = config["ConfigData"]["AppIdQuotaConfigs"].AsArray();
            var foundAppQuota = appQuotas.Where(s => s["AppId"].GetValue<string>() == appIdQuota.AppId).FirstOrDefault();
            if (foundAppQuota == null)
            {
                throw new UserException($"AppQuota with AppId '{appIdQuota.AppId}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}' was not found in config config");
            }

            appQuotas.Remove(foundAppQuota);

            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);

            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
        }

        /// <summary>
        /// Updates an existing application quota in the configuration for the specified model and traffic group.
        /// </summary>
        /// <param name="modelName">Model Name</param>
        /// <param name="trafficGroup">Traffic Group</param>
        /// <param name="appIdQuota">Application ID Quota</param>
        /// <param name="commandContext">Command Context</param>
        public void UpdateAppQuota(string modelName, string trafficGroup, AppIdQuota appIdQuota, CommandContext commandContext)
        {
            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
            var appQuotas = config["ConfigData"]["AppIdQuotaConfigs"].AsArray();
            var foundAppQuota = appQuotas.Where(s => s["AppId"].GetValue<string>() == appIdQuota.AppId).FirstOrDefault();
            if (foundAppQuota == null)
            {
                throw new UserException($"AppQuota with AppId '{appIdQuota.AppId}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}' was not found in config config");
            }

            var parsedFoundAppQuota = JsonSerializer.Deserialize<AppIdQuota>(foundAppQuota.ToJsonString());
            if (parsedFoundAppQuota == appIdQuota)
            {
                throw new UserException($"Attempting to update AppQuota with same exact values, AppId '{appIdQuota.AppId}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}'");
            }

            var patchAppQuotaObject = JsonSerializer.SerializeToNode(appIdQuota, IgnoreNullJsonOptions).AsObject();
            var mergedAppQuotaObject = foundAppQuota.AsObject().Merge(patchAppQuotaObject);
            if (appIdQuota.CapacityRatioNotSubjectToBorrowing == null
                && mergedAppQuotaObject.ContainsKey("CapacityRatioNotSubjectToBorrowing"))
            {
                mergedAppQuotaObject.Remove("CapacityRatioNotSubjectToBorrowing");
            }

            foundAppQuota.ReplaceWith(mergedAppQuotaObject);

            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);

            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
        }

        /// <summary>
        /// Creates a new endpoint for a specific model and traffic group.
        /// </summary>
        /// <param name="modelName">Model name</param>
        /// <param name="trafficGroup">Traffic group</param>
        /// <param name="endpoint">Endpoint to create</param>
        /// <param name="commandContext">Command Context</param>
        public void CreateEndpoint(string modelName, string trafficGroup, Endpoint endpoint, CommandContext commandContext)
        {
            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
            var endpoints = config["ConfigData"]["EndpointConfigs"].AsArray();

            // Validate the input.
            if (endpoint == null)
            {
                throw new UserException("Endpoint cannot be null");
            }

            // Sanitize URL: strip invisible Unicode characters and validate ASCII-only.
            var urlResult = CodexCore.Util.InputSanitizer.SanitizeUrl(endpoint.URL);
            if (!urlResult.Success)
            {
                throw new UserException($"Invalid endpoint URL: {urlResult.ErrorMessage}");
            }

            endpoint.URL = urlResult.Value;

            if (string.IsNullOrWhiteSpace(endpoint.URL))
            {
                throw new UserException("URL in Endpoint cannot be null or empty");
            }
            else if (endpoints.Where(s => s["URL"].GetValue<string>() == endpoint.URL).Any())
            {
                throw new UserException($"Endpoint with URL {endpoint.URL} already exists");
            }
            else if (endpoint.GlobalId != 0)
            {
                throw new UserException("GlobalId in Endpoint must be 0 for new endpoints");
            }

            int maxGlobalId = endpoints.Any() ? endpoints.Max(s => s["GlobalId"].GetValue<int>()) : 0;
            endpoint.GlobalId = maxGlobalId + 1;

            endpoints.Add(JsonSerializer.SerializeToNode(endpoint, IgnoreNullJsonOptions));

            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);

            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
        }

        /// <summary>
        /// Deletes the endpoint entry for the specified endpoint from the configuration associated with
        /// the given model name and traffic group.
        /// </summary>
        /// <param name="modelName">Model name.</param>
        /// <param name="trafficGroup">Traffic group.</param>
        /// <param name="endpoint">Endpoint to delete.</param>
        /// <param name="commandContext">Command Context.</param>
        public void DeleteEndpoint(string modelName, string trafficGroup, Endpoint endpoint, CommandContext commandContext)
        {
            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
            var endpoints = config["ConfigData"]["EndpointConfigs"].AsArray();
            var foundEp = endpoints
                    .Where(s => s["GlobalId"].GetValue<int>() == endpoint.GlobalId && s["URL"].GetValue<string>() == endpoint.URL)
                    .FirstOrDefault();
            if (foundEp == null)
            {
                throw new UserException($"Endpoint: GlobalId: '{endpoint.GlobalId}' URL: '{endpoint.URL}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}' was not found in config config");
            }

            endpoints.Remove(foundEp);

            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);

            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
        }

        /// <summary>
        /// Updates an existing endpoint in the configuration for the specified model and traffic group.
        /// </summary>
        /// <param name="modelName">Model Name.</param>
        /// <param name="trafficGroup">Traffic Group.</param>
        /// <param name="endpoint">Endpoint to update.</param>
        /// <param name="commandContext">Command Context.</param>
        public void UpdateEndpoint(string modelName, string trafficGroup, Endpoint endpoint, CommandContext commandContext)
        {
            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
            var endpoints = config["ConfigData"]["EndpointConfigs"].AsArray();
            var foundEp = endpoints
                    .Where(s => s["GlobalId"].GetValue<int>() == endpoint.GlobalId)
                    .FirstOrDefault();
            if (foundEp == null)
            {
                throw new UserException($"Endpoint with GlobalId '{endpoint.GlobalId}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}' was not found in config config");
            }

            var parsedFoundEp = JsonSerializer.Deserialize<Endpoint>(foundEp.ToJsonString());
            if (parsedFoundEp == endpoint)
            {
                throw new UserException($"Attempting to update Endpoint with same exact values, GlobalId '{endpoint.GlobalId}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}'");
            }

            var patchEQObject = JsonSerializer.SerializeToNode(endpoint, IgnoreNullJsonOptions).AsObject();
            var mergedObject = foundEp.AsObject().Merge(patchEQObject);
            if (endpoint.MaxConcurrencyPerInstance == null
                && mergedObject.ContainsKey("MaxConcurrencyPerInstance"))
            {
                mergedObject.Remove("MaxConcurrencyPerInstance");
            }

            if (endpoint.SafeConcurrencyPerInstance == null
                && mergedObject.ContainsKey("SafeConcurrencyPerInstance"))
            {
                mergedObject.Remove("SafeConcurrencyPerInstance");
            }

            foundEp.ReplaceWith(mergedObject);
            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);

            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
        }

        /// <summary>
        /// Create a new ModelTrafficGroupConfig entry in the Papyrus Control configuration.
        /// </summary>
        /// <param name="modelName">Model name.</param>
        /// <param name="trafficGroup">Traffic group.</param>
        /// <param name="modelTrafficGroupDetails">Model traffic group details.</param>
        /// <param name="glbName">GLB name (Needed to create the path name).</param>
        /// <param name="commandContext">Command Context.</param>
        public void CreateModelTrafficGroup(string modelName, string trafficGroup, ModelTrafficGroupDetails modelTrafficGroupDetails, string glbName, CommandContext commandContext)
        {
            if (this.GetModelTrafficGroupConfigJsonHelper(modelName, trafficGroup)?.Any() == true)
            {
                throw new UserException($"ModelTrafficGroup with ModelName '{modelName}' & TrafficGroup '{trafficGroup}' already exists in config config");
            }

            var configData = new ModelTrafficGroupConfigData
            {
                EndpointConfigs = [],
                AppIdQuotaConfigs = [],
                ModelConfigDetails = modelTrafficGroupDetails,
            };
            var modelNameTrafficGroupRow = new ModelTrafficGroupConfig
            {
                ModelTrafficGroup = new ModelTrafficGroup { ModelName = modelName, TrafficGroup = trafficGroup },
                ConfigData = configData,
            };

            var node = JsonSerializer.SerializeToNode(modelNameTrafficGroupRow).AsObject();
            node["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(node["ConfigData"]);

            var filePath = $"{this.SingleModelConfigFolderPath}{glbName}/{modelName}_{trafficGroup}.json";
            this.SingleModelConfigJsons[filePath] = new JsonObject
            {
                ["SkipStaging"] = false, // TODO: Get skip staging value from the user.
                ["ModelTrafficGroupConfig"] = node,
            };

            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Add);
        }

        /// <summary>
        /// Deletes the ModelTrafficGroupConfig entry from the Papyrus Control configuration.
        /// </summary>
        /// <param name="modelName">Model name.</param>
        /// <param name="trafficGroup">Traffic group.</param>
        /// <param name="commandContext">Command Context.</param>
        public void DeleteModelTrafficGroup(string modelName, string trafficGroup, CommandContext commandContext)
        {
            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
            this.SingleModelConfigJsons.Remove(fileChanged);
            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Delete);
        }

        /// <summary>
        /// Updates the ModelTrafficGroupDetails for the specified model and traffic group.
        /// </summary>
        /// <param name="modelName">Model name.</param>
        /// <param name="trafficGroup">Traffic group.</param>
        /// <param name="modelTrafficGroupDetails">Model traffic group details.</param>
        /// <param name="commandContext">Command Context.</param>
        public void UpdateModelTrafficGroupDetails(string modelName, string trafficGroup, ModelTrafficGroupDetails modelTrafficGroupDetails, CommandContext commandContext)
        {
            var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
            var existingDetails = config["ConfigData"]["ModelConfigDetails"].AsObject();

            var parsedExistingDetails = JsonSerializer.Deserialize<ModelTrafficGroupDetails>(existingDetails.ToJsonString());
            if (parsedExistingDetails == modelTrafficGroupDetails)
            {
                throw new UserException($"Attempting to update ModelTrafficGroupDetails with same exact values, ModelName '{modelName}' & TrafficGroup '{trafficGroup}'");
            }

            var patchDetailsObject = JsonSerializer.SerializeToNode(modelTrafficGroupDetails).AsObject();
            var mergedDetailsObject = existingDetails.Merge(patchDetailsObject);
            config["ConfigData"]["ModelConfigDetails"] = mergedDetailsObject;
            config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);

            var fileChanged = this.GetConfigFile(modelName, trafficGroup);
            commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
        }

        /// <summary>
        /// Gets the file path of the configuration file associated with the specified model name and traffic group.
        /// </summary>
        /// <param name="modelName">The name of the model to locate in the configuration files. Cannot be null.</param>
        /// <param name="trafficGroup">The name of the traffic group to locate in the configuration files. Cannot be null.</param>
        /// <returns>The file path of the configuration file that matches the specified model name and traffic group.</returns>
        private string GetConfigFile(string modelName, string trafficGroup)
        {
            // Check in single model config files
            foreach (var kvp in this.SingleModelConfigJsons)
            {
                var config = kvp.Value;
                var configs = config["ModelTrafficGroupConfig"].AsObject();
                if (configs != null)
                {
                    var mtg = configs["ModelTrafficGroup"].AsObject();
                    if (mtg != null &&
                        mtg["ModelName"].GetValue<string>() == modelName &&
                        mtg["TrafficGroup"].GetValue<string>() == trafficGroup)
                    {
                        return kvp.Key;
                    }
                }
            }

            throw new UserException($"Unable to find specified traffic group - ModelName: {modelName}, TrafficGroup: {trafficGroup}");
        }

        /// <summary>
        /// Helper method top retrieve model traffic group config json nodes.
        /// Does not validate existence.
        /// </summary>
        /// <param name="modelName">Model name.</param>
        /// <param name="trafficGroup">Traffic group.</param>
        /// <returns>The appropriate nodes (if any).</returns>
        private JsonObject GetModelTrafficGroupConfigJsonHelper(string modelName, string trafficGroup)
        {
            var configs = this.SingleModelConfigJsons.Values
                    .Select(s => s["ModelTrafficGroupConfig"])
                    .Where(cr => cr["ModelTrafficGroup"]["ModelName"].GetValue<string>() == modelName
                           && cr["ModelTrafficGroup"]["TrafficGroup"].GetValue<string>() == trafficGroup);
            return configs.FirstOrDefault()?.AsObject() ?? null;
        }

        /// <summary>
        /// Computes the hash of the given JsonNode deserialized as type T.
        /// </summary>
        /// <typeparam name="T">Type of object</typeparam>
        /// <param name="jsonNode">Json node.</param>
        /// <returns>Hash.</returns>
        private string ComputeHash<T>(JsonNode jsonNode)
        {
            var configData = JsonSerializer.Deserialize<T>(jsonNode.ToJsonString());
            return configData.ComputeHash();
        }
    }
}

