  6→namespace CodeXCore.Services
  7→{
  8→    using System;
  9→    using System.Collections.Generic;
 10→    using System.Linq;
 11→    using System.Security.Claims;
 12→    using System.Threading.Tasks;
 13→    using CodexCore.Models.DTOs.PapyrusConfig;
 14→    using CodexCore.Util;
 15→    using CodeXCore.ViewModel;
 16→    using ICodexLib.AOAI;
 17→    using ICodexLib.Common;
 18→    using Microsoft.Falcon.LibOnePortal.Utility;
 19→
 20→    /// <summary>
 21→    /// Class for Papyrus Config Validation.
 22→    /// </summary>
 23→    public class PapyrusConfigChangeValidator : IPapyrusConfigChangeValidator
 24→    {
 25→        /// <summary>
 26→        /// codex service.
 27→        /// </summary>
 28→        private readonly ICodeXService codexService;
 29→
 30→        /// <summary>
 31→        /// AOAI Client.
 32→        /// </summary>
 33→        private readonly IAOAIClient aoaiClient;
 34→
 35→        /// <summary>
 36→        /// Role permission service used to evaluate user permissions.
 37→        /// </summary>
 38→        private readonly IRolePermissionService rolePermissionService;
 39→
 40→        /// <summary>
 41→        /// The Papyrus configuration service.
 42→        /// </summary>
 43→        private readonly IPapyrusConfigService configSvc;
 44→
 45→        /// <summary>
 46→        /// Initializes a new instance of the <see cref="PapyrusConfigChangeValidator" /> class.
 47→        /// </summary>
 48→        /// /// <param name="codexService"><see cref="ICodeXService" /></param>
 49→        /// <param name="aoaiClient"><see cref="IAOAIClient" /></param>
 50→        /// <param name="rolePermissionService"><see cref="IRolePermissionService"/></param>
 51→        /// <param name="configSvc">Papyrus config Service.</param>
 52→        public PapyrusConfigChangeValidator(
 53→            ICodeXService codexService,
 54→            IAOAIClient aoaiClient,
 55→            IRolePermissionService rolePermissionService,
 56→            IPapyrusConfigService configSvc)
 57→        {
 58→            this.codexService = codexService ?? throw new ArgumentNullException(nameof(codexService));
 59→            this.aoaiClient = aoaiClient ?? throw new ArgumentNullException(nameof(aoaiClient));
 60→            this.rolePermissionService = rolePermissionService ?? throw new ArgumentNullException(nameof(rolePermissionService));
 61→            this.configSvc = configSvc ?? throw new ArgumentNullException(nameof(configSvc));
 62→        }
 63→
 64→        /// <inheritdoc/>
 65→        public async Task<ValidationResult> ValidateConfigChangeSetAsync(PapyrusConfigChangeSet changeSet, ClaimsPrincipal user)
 66→        {
 67→            if (changeSet == null)
 68→            {
 69→                throw new ArgumentNullException(nameof(changeSet));
 70→            }
 71→
 72→            var permissions = await this.rolePermissionService.GetUserRolePermissionsAsync(user);
 73→            var userIsAdmin = permissions.HasRole(RolePermissionConstants.Roles.Admin, RolePermissionConstants.Namespaces.Papyrus);
 74→
 75→            if (string.IsNullOrEmpty(changeSet.Title))
 76→            {
 77→                return new ValidationResult(false, "PR Title missing");
 78→            }
 79→
 80→            if (string.IsNullOrEmpty(changeSet.Description))
 81→            {
 82→                return new ValidationResult(false, "PR Description missing");
 83→            }
 84→
 85→            if (changeSet.EndpointCreateCommands.Any(createCommand => createCommand.EndpointConfig.Weight < 0))
 86→            {
 87→                return new ValidationResult(false, "Endpoint Weight must be a non-negative number");
 88→            }
 89→
 90→            foreach (var endpointCreateCommand in changeSet.EndpointCreateCommands)
 91→            {
 92→                var urlSanitizeResult = InputSanitizer.SanitizeUrl(endpointCreateCommand.EndpointConfig.URL);
 93→                if (!urlSanitizeResult.Success)
 94→                {
 95→                    return new ValidationResult(false, $"Invalid endpoint URL: {urlSanitizeResult.ErrorMessage}");
 96→                }
 97→
 98→                endpointCreateCommand.EndpointConfig.URL = urlSanitizeResult.Value;
 99→            }
100→
101→            foreach (var endpointUpdateCommand in changeSet.EndpointUpdateCommands)
102→            {
103→                if (!string.IsNullOrWhiteSpace(endpointUpdateCommand.EndpointConfig.URL))
104→                {
105→                    var urlSanitizeResult = InputSanitizer.SanitizeUrl(endpointUpdateCommand.EndpointConfig.URL);
106→                    if (!urlSanitizeResult.Success)
107→                    {
108→                        return new ValidationResult(false, $"Invalid endpoint URL: {urlSanitizeResult.ErrorMessage}");
109→                    }
110→
111→                    endpointUpdateCommand.EndpointConfig.URL = urlSanitizeResult.Value;
112→                }
113→            }
114→
115→            // Validate that all newly created GLBs have at least one quota (appid) configured
116→            var newGlbsWithoutQuotas = (changeSet.ModelTrafficGroupCreateCommands ?? Enumerable.Empty<ModelTrafficGroupCreateCommand>())
117→                .Where(glb =>
118→                    !string.IsNullOrWhiteSpace(glb.ModelName) &&
119→                    !string.IsNullOrWhiteSpace(glb.TrafficGroup) &&
120→                    !(changeSet.AppQuotaCreateCommands ?? Enumerable.Empty<AppQuotaCreateCommand>()).Any(q =>
121→                        string.Equals(q.ModelName?.Trim(), glb.ModelName?.Trim(), StringComparison.OrdinalIgnoreCase) &&
122→                        string.Equals(q.TrafficGroup?.Trim(), glb.TrafficGroup?.Trim(), StringComparison.OrdinalIgnoreCase)))
123→                .Select(glb => $"{glb.ModelName?.Trim()} / {glb.TrafficGroup?.Trim()}")
124→                .ToList();
125→
126→            if (newGlbsWithoutQuotas.Any())
127→            {
128→                return new ValidationResult(false, $"All newly created GLBs must have at least one quota (appid) configured. Missing: {string.Join(", ", newGlbsWithoutQuotas)}");
129→            }
130→
131→            var hasAppQuotaCommands = changeSet.AppQuotaCreateCommands.Any()
132→                || changeSet.AppQuotaUpdateCommands.Any()
133→                || changeSet.AppQuotaDeleteCommands.Any();
134→
135→            // Validate AppQuota commands' change values - create/delete/update quota as owners
136→            if (!userIsAdmin && hasAppQuotaCommands)
137→            {
138→                var ownedModelTrafficGroups = GetOwnedModelTrafficGroupKeys(permissions);
139→
140→                // GLBs being created in this changeset are treated as owned by the submitter
141→                var glbsBeingCreated = (changeSet.ModelTrafficGroupCreateCommands ?? Enumerable.Empty<ModelTrafficGroupCreateCommand>())
142→                    .Select(cmd => $"{cmd.ModelName}-{cmd.TrafficGroup}")
143→                    .Where(key => !string.IsNullOrWhiteSpace(key))
144→                    .ToHashSet(StringComparer.OrdinalIgnoreCase);
145→
146→                var targetModelTrafficGroups = changeSet.GetAppQuotaModelTrafficGroupKeys()
147→                    .Where(key => !string.IsNullOrWhiteSpace(key))
148→                    .Distinct(StringComparer.OrdinalIgnoreCase)
149→                    .ToList();
150→
151→                var nonOwnedModelTrafficGroups = targetModelTrafficGroups
152→                    .Where(key => !ownedModelTrafficGroups.Contains(key) && !glbsBeingCreated.Contains(key))
153→                    .ToHashSet(StringComparer.OrdinalIgnoreCase);
154→
155→                if (nonOwnedModelTrafficGroups.Any())
156→                {
157→                    var appQuotas = await this.configSvc.GetPapyrusControlAppQuotasAsync();
158→
159→                    var allQuotaDeltas = new List<AppQuotaUpdateDelta>();
160→
161→                    // Handle update commands (existing logic)
162→                    var updateDeltas = changeSet.AppQuotaUpdateCommands.Select(command =>
163→                    {
164→                        var originalQuotaValue = appQuotas.FirstOrDefault(appQuota =>
165→                            (appQuota.ModelName == command.ModelName) &&
166→                            (appQuota.TrafficGroup == command.TrafficGroup) &&
167→                            (appQuota.AppQuotaConfig.AppId == command.AppQuotaConfig.AppId))?.AppQuotaConfig.OnlineQuota ?? 0;
168→                        return new AppQuotaUpdateDelta(
169→                            command.ModelName,
170→                            command.TrafficGroup,
171→                            command.AppQuotaConfig.AppId,
172→                            command.AppQuotaConfig.OnlineQuota - originalQuotaValue);
173→                    });
174→
175→                    // Handle create commands (new quota = positive delta)
176→                    var createDeltas = changeSet.AppQuotaCreateCommands.Select(command =>
177→                        new AppQuotaUpdateDelta(
178→                            command.ModelName,
179→                            command.TrafficGroup,
180→                            command.AppQuotaConfig.AppId,
181→                            command.AppQuotaConfig.OnlineQuota)); // Full quota value as positive delta
182→
183→                    // Handle delete commands (removed quota = negative delta)
184→                    var deleteDeltas = changeSet.AppQuotaDeleteCommands.Select(command =>
185→                    {
186→                        var existingQuotaValue = appQuotas.FirstOrDefault(appQuota =>
187→                            (appQuota.ModelName == command.ModelName) &&
188→                            (appQuota.TrafficGroup == command.TrafficGroup) &&
189→                            (appQuota.AppQuotaConfig.AppId == command.AppQuotaConfig.AppId))?.AppQuotaConfig.OnlineQuota ?? 0;
190→                        return new AppQuotaUpdateDelta(
191→                            command.ModelName,
192→                            command.TrafficGroup,
193→                            command.AppQuotaConfig.AppId,
194→                            -existingQuotaValue); // Negative delta for deletion
195→                    });
196→
197→                    // Combine all deltas
198→                    allQuotaDeltas.AddRange(updateDeltas);
199→                    allQuotaDeltas.AddRange(createDeltas);
200→                    allQuotaDeltas.AddRange(deleteDeltas);
201→
202→                    var deltasToValidate = allQuotaDeltas
203→                        .Where(delta => nonOwnedModelTrafficGroups.Contains($"{delta.ModelName}-{delta.TrafficGroup}"))
204→                        .ToList();
205→
206→                    if (deltasToValidate.Any())
207→                    {
208→                        // Quota change validation is done across all apps under the same organization within the same model name and traffic group pair.
209→                        var changeDict = deltasToValidate
210→                            .GroupBy(item => $"{item.ModelName}-{item.TrafficGroup}.{PapyrusUtils.GetOrgNameFromAppId(item.AppId)}")
211→                            .ToDictionary(
212→                                group => group.Key,
213→                                group => group.Sum(item => item.QuotaChange));
214→
215→                        foreach (var appOrganizationChange in changeDict)
216→                        {
217→                            if (appOrganizationChange.Value != 0)
218→                            {
219→                                return new ValidationResult(false, $"App Organization '{appOrganizationChange.Key}' has a non-zero quota change across all apps under this organization. Net change: {appOrganizationChange.Value / 1000}. You must balance quota additions with quota reductions within the same organization and model-traffic group.");
220→                            }
221→                        }
222→                    }
223→                }
224→            }
225→
226→            if (changeSet.ServiceAuthQuotaCreateCommands.Any() || changeSet.ServiceAuthQuotaUpdateCommands.Any())
227→            {
228→                return this.ValidateChangeSetGuids(changeSet);
229→            }
230→
231→            return new ValidationResult(true, null);
232→        }
