234→        /// <inheritdoc/>
235→        public async Task<ValidationResult> CheckConfigChangeSetAuthorizationAsync(PapyrusConfigChangeSet changeSet, ClaimsPrincipal user)
236→        {
237→            var permissions = await this.rolePermissionService.GetUserRolePermissionsAsync(user);
238→            var userIsAdmin = permissions.HasRole(RolePermissionConstants.Roles.Admin, RolePermissionConstants.Namespaces.Papyrus);
239→
240→            // If local environment is in test mode, userAlias uses the Mock Test User alias instead of the alias from the token
241→            var userAlias = PermissionHelper.GetUserAlias(user);
242→            var userIsCodexUser = permissions.HasRole(RolePermissionConstants.Roles.User, RolePermissionConstants.Namespaces.Papyrus);
243→
244→            // TODO: Consider accumulating multiple authorization/validation errors instead of returning on first failure.
245→            if (!userIsAdmin && !userIsCodexUser)
246→            {
247→                return new ValidationResult(false, $"User with alias '{userAlias}' must be a Codex portal user to submit PR requests");
248→            }
249→
250→            if (changeSet.AutoMerge && !userIsAdmin)
251→            {
252→                var autoMergeValidation = ValidateAutoMergePermissions(changeSet, permissions);
253→                if (!autoMergeValidation.Result)
254→                {
255→                    return autoMergeValidation;
256→                }
257→            }
258→
259→            // Handle app quota commands (create/delete/update) - allow organization owners
260→            if (changeSet.AppQuotaCreateCommands.Any() ||
261→                changeSet.AppQuotaDeleteCommands.Any() ||
262→                changeSet.AppQuotaUpdateCommands.Any())
263→            {
264→                if (!userIsAdmin)
265→                {
266→                    // Combine all app IDs from create, delete, and update commands
267→                    var allAppIds = changeSet.AppQuotaCreateCommands.Select(cmd => cmd.AppQuotaConfig.AppId)
268→                        .Concat(changeSet.AppQuotaDeleteCommands.Select(cmd => cmd.AppQuotaConfig.AppId))
269→                        .Concat(changeSet.AppQuotaUpdateCommands.Select(cmd => cmd.AppQuotaConfig.AppId))
270→                        .ToList();
271→
272→                    var ownershipValidation = await this.ValidateOrganizationOwnershipAsync(user, allAppIds, userAlias);
273→                    if (!ownershipValidation.Result)
274→                    {
275→                        return ownershipValidation;
276→                    }
277→                }
278→            }
279→
280→            if ((changeSet.ServiceAuthQuotaDeleteCommands.Any() ||
281→                changeSet.ServiceAuthQuotaUpdateCommands.Any()) &&
282→                !userIsAdmin)
283→            {
284→                var targetQuotaAppIds = changeSet.ServiceAuthQuotaDeleteCommands.Select(cmd => cmd.QuotaAppId)
285→                    .Concat(changeSet.ServiceAuthQuotaUpdateCommands.Select(cmd => cmd.QuotaAppId))
286→                    .ToList();
287→
288→                var ownershipValidation = await this.ValidateOrganizationOwnershipAsync(user, targetQuotaAppIds, userAlias);
289→                if (!ownershipValidation.Result)
290→                {
291→                    return ownershipValidation;
292→                }
293→            }
294→
295→            return new ValidationResult(true, null);
296→        }
