298→        /// <summary>
299→        /// Validate that all GUIDs in the ServiceAuthQuota commands are valid GUIDs.
300→        /// </summary>
301→        /// <param name="changeSet">the request contains the changes</param>
302→        /// <returns>true if validate, false otherwise</returns>
303→        public ValidationResult ValidateChangeSetGuids(PapyrusConfigChangeSet changeSet)
304→        {
305→            if (!changeSet.ServiceAuthQuotaCreateCommands.Any() &&
306→                !changeSet.ServiceAuthQuotaUpdateCommands.Any())
307→            {
308→                return new ValidationResult(true, null);
309→            }
310→
311→            var invalidServiceTreeIds = changeSet.ServiceAuthQuotaCreateCommands.Select(s => s.ServiceTreeId)
312→                ?.Concat(changeSet.ServiceAuthQuotaUpdateCommands.Select(s => s.ServiceTreeId))
313→                ?.Where(id => !IsValidGuid(id))
314→                ?.ToList();
315→
316→            if (invalidServiceTreeIds.Any())
317→            {
318→                return new ValidationResult(false, $"Invalid ServiceTreeIds found: {string.Join(", ", invalidServiceTreeIds)}");
319→            }
320→
321→            var invalidAppIds = (changeSet.ServiceAuthQuotaCreateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementCreateCommand>()).SelectMany(s => s.AppIds ?? Enumerable.Empty<string>())
322→                .Concat((changeSet.ServiceAuthQuotaUpdateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementUpdateCommand>()).SelectMany(s => s.AppIds ?? Enumerable.Empty<string>()))
323→                .Where(id => id != null && !IsValidGuid(id))
324→                .ToList();
325→
326→            if (invalidAppIds.Any())
327→            {
328→                return new ValidationResult(false, $"Invalid AppIds found: {string.Join(", ", invalidAppIds)}");
329→            }
330→
331→            var invalidRoles = (changeSet.ServiceAuthQuotaCreateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementCreateCommand>()).SelectMany(s => s.Roles ?? Enumerable.Empty<string>())
332→                .Concat((changeSet.ServiceAuthQuotaUpdateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementUpdateCommand>()).SelectMany(s => s.Roles ?? Enumerable.Empty<string>()))
333→                .Where(id => !IsValidGuid(id))
334→                .ToList();
335→
336→            if (invalidRoles.Any())
337→            {
338→                return new ValidationResult(false, $"Invalid Roles found: {string.Join(", ", invalidRoles)}");
339→            }
340→
341→            return new ValidationResult(true, null);
342→        }
