349→        private static bool HasOwnershipForAppId(string appId, ISet<string> ownedAppIds)
350→        {
351→            if (string.IsNullOrWhiteSpace(appId) || ownedAppIds == null || ownedAppIds.Count == 0)
352→            {
353→                return false;
354→            }
355→
356→            var normalized = appId.Trim();
357→            while (!string.IsNullOrEmpty(normalized))
358→            {
359→                if (ownedAppIds.Contains(normalized))
360→                {
361→                    return true;
362→                }
363→
364→                var separatorIndex = normalized.LastIndexOf('/');
365→                if (separatorIndex <= 0)
366→                {
367→                    break;
368→                }
369→
370→                normalized = normalized.Substring(0, separatorIndex);
371→            }
372→
373→            return false;
374→        }
