376→        private static ValidationResult ValidateAutoMergePermissions(PapyrusConfigChangeSet changeSet, UserRolePermissions permissions)
377→        {
378→            var ownedModelTrafficGroups = GetOwnedModelTrafficGroupKeys(permissions);
379→
380→            var glbsBeingCreated = (changeSet.ModelTrafficGroupCreateCommands ?? Enumerable.Empty<ModelTrafficGroupCreateCommand>())
381→                .Select(cmd => $"{cmd.ModelName}-{cmd.TrafficGroup}")
382→                .Where(key => !string.IsNullOrWhiteSpace(key))
383→                .ToHashSet(StringComparer.OrdinalIgnoreCase);
384→
385→            var mtgKeys = NormalizeDistinct(GetModelTrafficGroupKeysRequiringOwnership(changeSet));
386→            var nonOwnedMtgKeys = GetNonOwnedKeys(mtgKeys, ownedModelTrafficGroups, glbsBeingCreated);
387→            if (nonOwnedMtgKeys.Any())
388→            {
389→                return new ValidationResult(
390→                    false,
391→                    $"Auto-approval requires model traffic group ownership for: {string.Join(", ", nonOwnedMtgKeys)}");
392→            }
393→
394→            var appQuotaCreateMtgKeys = NormalizeDistinct(GetAppQuotaCreateModelTrafficGroupKeys(changeSet));
395→            var nonOwnedAppQuotaCreateMtgKeys = GetNonOwnedKeys(appQuotaCreateMtgKeys, ownedModelTrafficGroups, glbsBeingCreated);
396→            if (nonOwnedAppQuotaCreateMtgKeys.Any())
397→            {
398→                return new ValidationResult(
399→                    false,
400→                    $"Auto-approval requires model traffic group ownership for new app quota entries: {string.Join(", ", nonOwnedAppQuotaCreateMtgKeys)}");
401→            }
402→
403→            var ownedQuotaAppIds = GetOwnedQuotaAppIds(permissions);
404→            var nonOwnedAppQuotaAppIds = GetNonOwnedQuotaAppIds(
405→                GetAppQuotaEntries(changeSet),
406→                ownedModelTrafficGroups,
407→                glbsBeingCreated,
408→                ownedQuotaAppIds);
409→            if (nonOwnedAppQuotaAppIds.Any())
410→            {
411→                return new ValidationResult(
412→                    false,
413→                    $"Auto-approval requires quota app ID ownership for: {string.Join(", ", nonOwnedAppQuotaAppIds)}");
414→            }
415→
416→            var targetQuotaAppIds = NormalizeDistinct(GetServiceAuthQuotaAppIds(changeSet));
417→            var nonOwnedServiceAuthQuotaAppIds = targetQuotaAppIds
418→                .Where(appId => !HasOwnershipForAppId(appId, ownedQuotaAppIds))
419→                .ToList();
420→
421→            if (nonOwnedServiceAuthQuotaAppIds.Any())
422→            {
423→                return new ValidationResult(
424→                    false,
425→                    $"Auto-approval requires service auth quota ownership for: {string.Join(", ", nonOwnedServiceAuthQuotaAppIds)}");
426→            }
427→
428→            return new ValidationResult(true, null);
429→        }
