534→        /// <summary>
535→        /// For app quota entries where the user does not own the model traffic group,
536→        /// checks quota app ID ownership as a fallback. Returns the non-owned app IDs.
537→        /// </summary>
538→        private static List<string> GetNonOwnedQuotaAppIds(
539→            IEnumerable<(string MtgKey, string AppId)> appQuotaEntries,
540→            ISet<string> ownedModelTrafficGroups,
541→            ISet<string> glbsBeingCreated,
542→            ISet<string> ownedQuotaAppIds)
543→        {
544→            var nonOwned = new HashSet<string>(StringComparer.OrdinalIgnoreCase);
545→
546→            foreach (var (mtgKey, appId) in appQuotaEntries)
547→            {
548→                if (string.IsNullOrWhiteSpace(appId))
549→                {
550→                    continue;
551→                }
552→
553→                // If the user owns the model traffic group, they're authorized for this entry
554→                if (!string.IsNullOrWhiteSpace(mtgKey) &&
555→                    (ownedModelTrafficGroups.Contains(mtgKey) || glbsBeingCreated.Contains(mtgKey)))
556→                {
557→                    continue;
558→                }
559→
560→                // Fall back to quota app ID ownership
561→                if (!HasOwnershipForAppId(appId, ownedQuotaAppIds))
562→                {
563→                    nonOwned.Add(appId);
564→                }
565→            }
566→
567→            return nonOwned.ToList();
568→        }
