593→        /// <summary>
594→        /// Validates that the user has owner permission for the organizations associated with the given app IDs.
595→        /// </summary>
596→        /// <param name="user">The user claims principal.</param>
597→        /// <param name="appIds">The application IDs to check organization ownership for.</param>
598→        /// <param name="userAlias">The user's alias for error messages.</param>
599→        /// <returns>A validation result indicating success or failure with appropriate error message.</returns>
600→        private async Task<ValidationResult> ValidateOrganizationOwnershipAsync(ClaimsPrincipal user, IEnumerable<string> appIds, string userAlias)
601→        {
602→            var targetAppIds = (appIds ?? Enumerable.Empty<string>())
603→                .Where(id => !string.IsNullOrWhiteSpace(id))
604→                .Distinct(StringComparer.OrdinalIgnoreCase)
605→                .ToList();
606→
607→            if (!targetAppIds.Any())
608→            {
609→                return new ValidationResult(true, null);
610→            }
611→
612→            var quotas = await this.configSvc.GetServiceQuotaAndAuthManagementAsync(userAlias);
613→            var quotaOwnersLookup = (quotas ?? new List<ServiceAuthQuotaManagement>())
614→                .GroupBy(q => q.QuotaAppId, StringComparer.OrdinalIgnoreCase)
615→                .ToDictionary(
616→                    group => group.Key,
617→                    group => group
618→                        .SelectMany(q => q.Owners ?? Enumerable.Empty<string>())
619→                        .Distinct(StringComparer.OrdinalIgnoreCase)
620→                        .ToList(),
621→                    StringComparer.OrdinalIgnoreCase);
622→
623→            var ownedAppIds = new HashSet<string>(
624→                quotaOwnersLookup.Keys
625→                    .Where(key => !string.IsNullOrWhiteSpace(key))
626→                    .Select(key => key.Trim()),
627→                StringComparer.OrdinalIgnoreCase);
628→
629→            var missingQuotas = targetAppIds
630→                .Where(appId => !HasOwnershipForAppId(appId, ownedAppIds))
631→                .ToList();
632→
633→            if (missingQuotas.Any())
634→            {
635→                var errors = new List<string>();
636→
637→                if (missingQuotas.Any())
638→                {
639→                    errors.Add($"Quotas not found or not owned: [{string.Join(", ", missingQuotas)}]");
640→                }
641→
642→                return new ValidationResult(false, string.Join(". ", errors));
643→            }
644→
645→            return new ValidationResult(true, null);
646→        }
647→
648→        private async Task<ValidationResult> ValidateDeploymentURLAsync(string url)
649→        {
650→            var urlWrapper = new DeploymentURLWrapper(url);
651→            if (urlWrapper.DeploymentURLType == DeploymentURLWrapper.DeploymentType.AML)
652→            {
653→                var exists = this.codexService.CheckEndpointInRegionExists(urlWrapper.URLTokens[0], urlWrapper.URLTokens[1]);
654→                if (!exists)
655→                {
656→                    return new ValidationResult(false, $"The following AML URL does not exist: {url}");
657→                }
658→            }
659→
660→            if (urlWrapper.DeploymentURLType == DeploymentURLWrapper.DeploymentType.AOAI)
661→            {
662→                var accountName = urlWrapper.URLTokens[0];
663→                var deploymentName = urlWrapper.URLTokens[1];
664→                var deploymentExistsResult = await this.aoaiClient.CheckAoaiDeploymentExistAsync(this.aoaiClient.SubscriptionID, this.aoaiClient.ResourceGroup, accountName, deploymentName);
665→                if (!deploymentExistsResult.Result)
