// --------------------------------------------------------------------
// <copyright file="PapyrusConfigChangeValidator.cs" company="Microsoft">
//   Copyright (c) Microsoft. All rights reserved.
// </copyright>
// --------------------------------------------------------------------
namespace CodeXCore.Services
{
    using System;
    using System.Collections.Generic;
    using System.Linq;
    using System.Security.Claims;
    using System.Threading.Tasks;
    using CodexCore.Models.DTOs.PapyrusConfig;
    using CodexCore.Util;
    using CodeXCore.ViewModel;
    using ICodexLib.AOAI;
    using ICodexLib.Common;
    using Microsoft.Falcon.LibOnePortal.Utility;

    /// <summary>
    /// Class for Papyrus Config Validation.
    /// </summary>
    public class PapyrusConfigChangeValidator : IPapyrusConfigChangeValidator
    {
        /// <summary>
        /// codex service.
        /// </summary>
        private readonly ICodeXService codexService;

        /// <summary>
        /// AOAI Client.
        /// </summary>
        private readonly IAOAIClient aoaiClient;

        /// <summary>
        /// Role permission service used to evaluate user permissions.
        /// </summary>
        private readonly IRolePermissionService rolePermissionService;

        /// <summary>
        /// The Papyrus configuration service.
        /// </summary>
        private readonly IPapyrusConfigService configSvc;

        /// <summary>
        /// Initializes a new instance of the <see cref="PapyrusConfigChangeValidator" /> class.
        /// </summary>
        /// /// <param name="codexService"><see cref="ICodeXService" /></param>
        /// <param name="aoaiClient"><see cref="IAOAIClient" /></param>
        /// <param name="rolePermissionService"><see cref="IRolePermissionService"/></param>
        /// <param name="configSvc">Papyrus config Service.</param>
        public PapyrusConfigChangeValidator(
            ICodeXService codexService,
            IAOAIClient aoaiClient,
            IRolePermissionService rolePermissionService,
            IPapyrusConfigService configSvc)
        {
            this.codexService = codexService ?? throw new ArgumentNullException(nameof(codexService));
            this.aoaiClient = aoaiClient ?? throw new ArgumentNullException(nameof(aoaiClient));
            this.rolePermissionService = rolePermissionService ?? throw new ArgumentNullException(nameof(rolePermissionService));
            this.configSvc = configSvc ?? throw new ArgumentNullException(nameof(configSvc));
        }

        /// <inheritdoc/>
        public async Task<ValidationResult> ValidateConfigChangeSetAsync(PapyrusConfigChangeSet changeSet, ClaimsPrincipal user)
        {
            if (changeSet == null)
            {
                throw new ArgumentNullException(nameof(changeSet));
            }

            var permissions = await this.rolePermissionService.GetUserRolePermissionsAsync(user);
            var userIsAdmin = permissions.HasRole(RolePermissionConstants.Roles.Admin, RolePermissionConstants.Namespaces.Papyrus);

            if (string.IsNullOrEmpty(changeSet.Title))
            {
                return new ValidationResult(false, "PR Title missing");
            }

            if (string.IsNullOrEmpty(changeSet.Description))
            {
                return new ValidationResult(false, "PR Description missing");
            }

            if (changeSet.EndpointCreateCommands.Any(createCommand => createCommand.EndpointConfig.Weight < 0))
            {
                return new ValidationResult(false, "Endpoint Weight must be a non-negative number");
            }

            foreach (var endpointCreateCommand in changeSet.EndpointCreateCommands)
            {
                var urlSanitizeResult = InputSanitizer.SanitizeUrl(endpointCreateCommand.EndpointConfig.URL);
                if (!urlSanitizeResult.Success)
                {
                    return new ValidationResult(false, $"Invalid endpoint URL: {urlSanitizeResult.ErrorMessage}");
                }

                endpointCreateCommand.EndpointConfig.URL = urlSanitizeResult.Value;
            }

            foreach (var endpointUpdateCommand in changeSet.EndpointUpdateCommands)
            {
                if (!string.IsNullOrWhiteSpace(endpointUpdateCommand.EndpointConfig.URL))
                {
                    var urlSanitizeResult = InputSanitizer.SanitizeUrl(endpointUpdateCommand.EndpointConfig.URL);
                    if (!urlSanitizeResult.Success)
                    {
                        return new ValidationResult(false, $"Invalid endpoint URL: {urlSanitizeResult.ErrorMessage}");
                    }

                    endpointUpdateCommand.EndpointConfig.URL = urlSanitizeResult.Value;
                }
            }

            // Validate that all newly created GLBs have at least one quota (appid) configured
            var newGlbsWithoutQuotas = (changeSet.ModelTrafficGroupCreateCommands ?? Enumerable.Empty<ModelTrafficGroupCreateCommand>())
                .Where(glb =>
                    !string.IsNullOrWhiteSpace(glb.ModelName) &&
                    !string.IsNullOrWhiteSpace(glb.TrafficGroup) &&
                    !(changeSet.AppQuotaCreateCommands ?? Enumerable.Empty<AppQuotaCreateCommand>()).Any(q =>
                        string.Equals(q.ModelName?.Trim(), glb.ModelName?.Trim(), StringComparison.OrdinalIgnoreCase) &&
                        string.Equals(q.TrafficGroup?.Trim(), glb.TrafficGroup?.Trim(), StringComparison.OrdinalIgnoreCase)))
                .Select(glb => $"{glb.ModelName?.Trim()} / {glb.TrafficGroup?.Trim()}")
                .ToList();

            if (newGlbsWithoutQuotas.Any())
            {
                return new ValidationResult(false, $"All newly created GLBs must have at least one quota (appid) configured. Missing: {string.Join(", ", newGlbsWithoutQuotas)}");
            }

            var hasAppQuotaCommands = changeSet.AppQuotaCreateCommands.Any()
                || changeSet.AppQuotaUpdateCommands.Any()
                || changeSet.AppQuotaDeleteCommands.Any();

            // Validate AppQuota commands' change values - create/delete/update quota as owners
            if (!userIsAdmin && hasAppQuotaCommands)
            {
                var ownedModelTrafficGroups = GetOwnedModelTrafficGroupKeys(permissions);

                // GLBs being created in this changeset are treated as owned by the submitter
                var glbsBeingCreated = (changeSet.ModelTrafficGroupCreateCommands ?? Enumerable.Empty<ModelTrafficGroupCreateCommand>())
                    .Select(cmd => $"{cmd.ModelName}-{cmd.TrafficGroup}")
                    .Where(key => !string.IsNullOrWhiteSpace(key))
                    .ToHashSet(StringComparer.OrdinalIgnoreCase);

                var targetModelTrafficGroups = changeSet.GetAppQuotaModelTrafficGroupKeys()
                    .Where(key => !string.IsNullOrWhiteSpace(key))
                    .Distinct(StringComparer.OrdinalIgnoreCase)
                    .ToList();

                var nonOwnedModelTrafficGroups = targetModelTrafficGroups
                    .Where(key => !ownedModelTrafficGroups.Contains(key) && !glbsBeingCreated.Contains(key))
                    .ToHashSet(StringComparer.OrdinalIgnoreCase);

                if (nonOwnedModelTrafficGroups.Any())
                {
                    var appQuotas = await this.configSvc.GetPapyrusControlAppQuotasAsync();

                    var allQuotaDeltas = new List<AppQuotaUpdateDelta>();

                    // Handle update commands (existing logic)
                    var updateDeltas = changeSet.AppQuotaUpdateCommands.Select(command =>
                    {
                        var originalQuotaValue = appQuotas.FirstOrDefault(appQuota =>
                            (appQuota.ModelName == command.ModelName) &&
                            (appQuota.TrafficGroup == command.TrafficGroup) &&
                            (appQuota.AppQuotaConfig.AppId == command.AppQuotaConfig.AppId))?.AppQuotaConfig.OnlineQuota ?? 0;
                        return new AppQuotaUpdateDelta(
                            command.ModelName,
                            command.TrafficGroup,
                            command.AppQuotaConfig.AppId,
                            command.AppQuotaConfig.OnlineQuota - originalQuotaValue);
                    });

                    // Handle create commands (new quota = positive delta)
                    var createDeltas = changeSet.AppQuotaCreateCommands.Select(command =>
                        new AppQuotaUpdateDelta(
                            command.ModelName,
                            command.TrafficGroup,
                            command.AppQuotaConfig.AppId,
                            command.AppQuotaConfig.OnlineQuota)); // Full quota value as positive delta

                    // Handle delete commands (removed quota = negative delta)
                    var deleteDeltas = changeSet.AppQuotaDeleteCommands.Select(command =>
                    {
                        var existingQuotaValue = appQuotas.FirstOrDefault(appQuota =>
                            (appQuota.ModelName == command.ModelName) &&
                            (appQuota.TrafficGroup == command.TrafficGroup) &&
                            (appQuota.AppQuotaConfig.AppId == command.AppQuotaConfig.AppId))?.AppQuotaConfig.OnlineQuota ?? 0;
                        return new AppQuotaUpdateDelta(
                            command.ModelName,
                            command.TrafficGroup,
                            command.AppQuotaConfig.AppId,
                            -existingQuotaValue); // Negative delta for deletion
                    });

                    // Combine all deltas
                    allQuotaDeltas.AddRange(updateDeltas);
                    allQuotaDeltas.AddRange(createDeltas);
                    allQuotaDeltas.AddRange(deleteDeltas);

                    var deltasToValidate = allQuotaDeltas
                        .Where(delta => nonOwnedModelTrafficGroups.Contains($"{delta.ModelName}-{delta.TrafficGroup}"))
                        .ToList();

                    if (deltasToValidate.Any())
                    {
                        // Quota change validation is done across all apps under the same organization within the same model name and traffic group pair.
                        var changeDict = deltasToValidate
                            .GroupBy(item => $"{item.ModelName}-{item.TrafficGroup}.{PapyrusUtils.GetOrgNameFromAppId(item.AppId)}")
                            .ToDictionary(
                                group => group.Key,
                                group => group.Sum(item => item.QuotaChange));

                        foreach (var appOrganizationChange in changeDict)
                        {
                            if (appOrganizationChange.Value != 0)
                            {
                                return new ValidationResult(false, $"App Organization '{appOrganizationChange.Key}' has a non-zero quota change across all apps under this organization. Net change: {appOrganizationChange.Value / 1000}. You must balance quota additions with quota reductions within the same organization and model-traffic group.");
                            }
                        }
                    }
                }
            }

            if (changeSet.ServiceAuthQuotaCreateCommands.Any() || changeSet.ServiceAuthQuotaUpdateCommands.Any())
            {
                return this.ValidateChangeSetGuids(changeSet);
            }

            return new ValidationResult(true, null);
        }

        /// <inheritdoc/>
        public async Task<ValidationResult> CheckConfigChangeSetAuthorizationAsync(PapyrusConfigChangeSet changeSet, ClaimsPrincipal user)
        {
            var permissions = await this.rolePermissionService.GetUserRolePermissionsAsync(user);
            var userIsAdmin = permissions.HasRole(RolePermissionConstants.Roles.Admin, RolePermissionConstants.Namespaces.Papyrus);

            // If local environment is in test mode, userAlias uses the Mock Test User alias instead of the alias from the token
            var userAlias = PermissionHelper.GetUserAlias(user);
            var userIsCodexUser = permissions.HasRole(RolePermissionConstants.Roles.User, RolePermissionConstants.Namespaces.Papyrus);

            // TODO: Consider accumulating multiple authorization/validation errors instead of returning on first failure.
            if (!userIsAdmin && !userIsCodexUser)
            {
                return new ValidationResult(false, $"User with alias '{userAlias}' must be a Codex portal user to submit PR requests");
            }

            if (changeSet.AutoMerge && !userIsAdmin)
            {
                var autoMergeValidation = ValidateAutoMergePermissions(changeSet, permissions);
                if (!autoMergeValidation.Result)
                {
                    return autoMergeValidation;
                }
            }

            // Handle app quota commands (create/delete/update) - allow organization owners
            if (changeSet.AppQuotaCreateCommands.Any() ||
                changeSet.AppQuotaDeleteCommands.Any() ||
                changeSet.AppQuotaUpdateCommands.Any())
            {
                if (!userIsAdmin)
                {
                    // Combine all app IDs from create, delete, and update commands
                    var allAppIds = changeSet.AppQuotaCreateCommands.Select(cmd => cmd.AppQuotaConfig.AppId)
                        .Concat(changeSet.AppQuotaDeleteCommands.Select(cmd => cmd.AppQuotaConfig.AppId))
                        .Concat(changeSet.AppQuotaUpdateCommands.Select(cmd => cmd.AppQuotaConfig.AppId))
                        .ToList();

                    var ownershipValidation = await this.ValidateOrganizationOwnershipAsync(user, allAppIds, userAlias);
                    if (!ownershipValidation.Result)
                    {
                        return ownershipValidation;
                    }
                }
            }

            if ((changeSet.ServiceAuthQuotaDeleteCommands.Any() ||
                changeSet.ServiceAuthQuotaUpdateCommands.Any()) &&
                !userIsAdmin)
            {
                var targetQuotaAppIds = changeSet.ServiceAuthQuotaDeleteCommands.Select(cmd => cmd.QuotaAppId)
                    .Concat(changeSet.ServiceAuthQuotaUpdateCommands.Select(cmd => cmd.QuotaAppId))
                    .ToList();

                var ownershipValidation = await this.ValidateOrganizationOwnershipAsync(user, targetQuotaAppIds, userAlias);
                if (!ownershipValidation.Result)
                {
                    return ownershipValidation;
                }
            }

            return new ValidationResult(true, null);
        }

        /// <summary>
        /// Validate that all GUIDs in the ServiceAuthQuota commands are valid GUIDs.
        /// </summary>
        /// <param name="changeSet">the request contains the changes</param>
        /// <returns>true if validate, false otherwise</returns>
        public ValidationResult ValidateChangeSetGuids(PapyrusConfigChangeSet changeSet)
        {
            if (!changeSet.ServiceAuthQuotaCreateCommands.Any() &&
                !changeSet.ServiceAuthQuotaUpdateCommands.Any())
            {
                return new ValidationResult(true, null);
            }

            var invalidServiceTreeIds = changeSet.ServiceAuthQuotaCreateCommands.Select(s => s.ServiceTreeId)
                ?.Concat(changeSet.ServiceAuthQuotaUpdateCommands.Select(s => s.ServiceTreeId))
                ?.Where(id => !IsValidGuid(id))
                ?.ToList();

            if (invalidServiceTreeIds.Any())
            {
                return new ValidationResult(false, $"Invalid ServiceTreeIds found: {string.Join(", ", invalidServiceTreeIds)}");
            }

            var invalidAppIds = (changeSet.ServiceAuthQuotaCreateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementCreateCommand>()).SelectMany(s => s.AppIds ?? Enumerable.Empty<string>())
                .Concat((changeSet.ServiceAuthQuotaUpdateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementUpdateCommand>()).SelectMany(s => s.AppIds ?? Enumerable.Empty<string>()))
                .Where(id => id != null && !IsValidGuid(id))
                .ToList();

            if (invalidAppIds.Any())
            {
                return new ValidationResult(false, $"Invalid AppIds found: {string.Join(", ", invalidAppIds)}");
            }

            var invalidRoles = (changeSet.ServiceAuthQuotaCreateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementCreateCommand>()).SelectMany(s => s.Roles ?? Enumerable.Empty<string>())
                .Concat((changeSet.ServiceAuthQuotaUpdateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementUpdateCommand>()).SelectMany(s => s.Roles ?? Enumerable.Empty<string>()))
                .Where(id => !IsValidGuid(id))
                .ToList();

            if (invalidRoles.Any())
            {
                return new ValidationResult(false, $"Invalid Roles found: {string.Join(", ", invalidRoles)}");
            }

            return new ValidationResult(true, null);
        }

        private static bool IsValidGuid(string input)
        {
            return !string.IsNullOrWhiteSpace(input) && Guid.TryParse(input, out _);
        }

        private static bool HasOwnershipForAppId(string appId, ISet<string> ownedAppIds)
        {
            if (string.IsNullOrWhiteSpace(appId) || ownedAppIds == null || ownedAppIds.Count == 0)
            {
                return false;
            }

            var normalized = appId.Trim();
            while (!string.IsNullOrEmpty(normalized))
            {
                if (ownedAppIds.Contains(normalized))
                {
                    return true;
                }

                var separatorIndex = normalized.LastIndexOf('/');
                if (separatorIndex <= 0)
                {
                    break;
                }

                normalized = normalized.Substring(0, separatorIndex);
            }

            return false;
        }

        private static ValidationResult ValidateAutoMergePermissions(PapyrusConfigChangeSet changeSet, UserRolePermissions permissions)
        {
            var ownedModelTrafficGroups = GetOwnedModelTrafficGroupKeys(permissions);

            var glbsBeingCreated = (changeSet.ModelTrafficGroupCreateCommands ?? Enumerable.Empty<ModelTrafficGroupCreateCommand>())
                .Select(cmd => $"{cmd.ModelName}-{cmd.TrafficGroup}")
                .Where(key => !string.IsNullOrWhiteSpace(key))
                .ToHashSet(StringComparer.OrdinalIgnoreCase);

            var mtgKeys = NormalizeDistinct(GetModelTrafficGroupKeysRequiringOwnership(changeSet));
            var nonOwnedMtgKeys = GetNonOwnedKeys(mtgKeys, ownedModelTrafficGroups, glbsBeingCreated);
            if (nonOwnedMtgKeys.Any())
            {
                return new ValidationResult(
                    false,
                    $"Auto-approval requires model traffic group ownership for: {string.Join(", ", nonOwnedMtgKeys)}");
            }

            var appQuotaCreateMtgKeys = NormalizeDistinct(GetAppQuotaCreateModelTrafficGroupKeys(changeSet));
            var nonOwnedAppQuotaCreateMtgKeys = GetNonOwnedKeys(appQuotaCreateMtgKeys, ownedModelTrafficGroups, glbsBeingCreated);
            if (nonOwnedAppQuotaCreateMtgKeys.Any())
            {
                return new ValidationResult(
                    false,
                    $"Auto-approval requires model traffic group ownership for new app quota entries: {string.Join(", ", nonOwnedAppQuotaCreateMtgKeys)}");
            }

            var ownedQuotaAppIds = GetOwnedQuotaAppIds(permissions);
            var nonOwnedAppQuotaAppIds = GetNonOwnedQuotaAppIds(
                GetAppQuotaEntries(changeSet),
                ownedModelTrafficGroups,
                glbsBeingCreated,
                ownedQuotaAppIds);
            if (nonOwnedAppQuotaAppIds.Any())
            {
                return new ValidationResult(
                    false,
                    $"Auto-approval requires quota app ID ownership for: {string.Join(", ", nonOwnedAppQuotaAppIds)}");
            }

            var targetQuotaAppIds = NormalizeDistinct(GetServiceAuthQuotaAppIds(changeSet));
            var nonOwnedServiceAuthQuotaAppIds = targetQuotaAppIds
                .Where(appId => !HasOwnershipForAppId(appId, ownedQuotaAppIds))
                .ToList();

            if (nonOwnedServiceAuthQuotaAppIds.Any())
            {
                return new ValidationResult(
                    false,
                    $"Auto-approval requires service auth quota ownership for: {string.Join(", ", nonOwnedServiceAuthQuotaAppIds)}");
            }

            return new ValidationResult(true, null);
        }

        private static HashSet<string> GetOwnedModelTrafficGroupKeys(UserRolePermissions permissions)
        {
            var comparer = StringComparer.OrdinalIgnoreCase;
            var roles = permissions?.Roles ?? Enumerable.Empty<RolePermission>();
            return roles
                .Where(role =>
                    comparer.Equals(role.Name, RolePermissionConstants.Roles.ModelTrafficGroupOwner) &&
                    comparer.Equals(role.Namespace, RolePermissionConstants.Namespaces.Papyrus))
                .Select(role => role.Metadata?.Trim())
                .Where(metadata => !string.IsNullOrWhiteSpace(metadata))
                .Select(metadata => metadata!) // <-- Add this to ensure non-null
                .ToHashSet(comparer);
        }

        private static HashSet<string> GetOwnedQuotaAppIds(UserRolePermissions permissions)
        {
            var comparer = StringComparer.OrdinalIgnoreCase;
            var roles = permissions?.Roles ?? Enumerable.Empty<RolePermission>();
            return roles
                .Where(role =>
                    comparer.Equals(role.Name, RolePermissionConstants.Roles.QuotaOwner) &&
                    comparer.Equals(role.Namespace, RolePermissionConstants.Namespaces.Papyrus))
                .Select(role => role.Metadata?.Trim())
                .Where(metadata => !string.IsNullOrWhiteSpace(metadata))
                .Select(metadata => metadata!) // <-- Add this to ensure non-null
                .ToHashSet(comparer);
        }

        /// <summary>
        /// Gets model traffic group keys from endpoint and model traffic group commands only (excludes AppQuota commands).
        /// </summary>
        private static IEnumerable<string> GetModelTrafficGroupKeysRequiringOwnership(PapyrusConfigChangeSet changeSet)
        {
            if (changeSet == null)
            {
                return Enumerable.Empty<string>();
            }

            return Enumerable.Empty<ModelConfigCommand>()
                .Concat(changeSet.EndpointCreateCommands ?? Enumerable.Empty<EndpointCreateCommand>())
                .Concat(changeSet.EndpointUpdateCommands ?? Enumerable.Empty<EndpointUpdateCommand>())
                .Concat(changeSet.EndpointDeleteCommands ?? Enumerable.Empty<EndpointDeleteCommand>())
                .Concat(changeSet.ModelTrafficGroupCreateCommands ?? Enumerable.Empty<ModelTrafficGroupCreateCommand>())
                .Concat(changeSet.ModelTrafficGroupUpdateCommands ?? Enumerable.Empty<ModelTrafficGroupUpdateCommand>())
                .Concat(changeSet.ModelTrafficGroupDeleteCommands ?? Enumerable.Empty<ModelTrafficGroupDeleteCommand>())
                .Select(cmd => $"{cmd.ModelName}-{cmd.TrafficGroup}");
        }

        /// <summary>
        /// Gets model traffic group keys from AppQuotaCreateCommands only.
        /// </summary>
        private static IEnumerable<string> GetAppQuotaCreateModelTrafficGroupKeys(PapyrusConfigChangeSet changeSet)
        {
            if (changeSet == null)
            {
                return Enumerable.Empty<string>();
            }

            return (changeSet.AppQuotaCreateCommands ?? Enumerable.Empty<AppQuotaCreateCommand>())
                .Select(cmd => $"{cmd.ModelName}-{cmd.TrafficGroup}");
        }

        /// <summary>
        /// Gets (ModelTrafficGroupKey, AppId) pairs from all AppQuota create/update/delete commands.
        /// </summary>
        private static IEnumerable<(string MtgKey, string AppId)> GetAppQuotaEntries(PapyrusConfigChangeSet changeSet)
        {
            if (changeSet == null)
            {
                return Enumerable.Empty<(string, string)>();
            }

            return Enumerable.Empty<ModelConfigCommand>()
                .Concat(changeSet.AppQuotaCreateCommands ?? Enumerable.Empty<AppQuotaCreateCommand>())
                .Concat(changeSet.AppQuotaUpdateCommands ?? Enumerable.Empty<AppQuotaUpdateCommand>())
                .Concat(changeSet.AppQuotaDeleteCommands ?? Enumerable.Empty<AppQuotaDeleteCommand>())
                .Select(cmd => ($"{cmd.ModelName}-{cmd.TrafficGroup}", ((IAppQuotaConfigCommand)cmd).AppQuotaConfig.AppId));
        }

        /// <summary>
        /// Filters and returns only the non-blank, distinct values from the input.
        /// </summary>
        private static List<string> NormalizeDistinct(IEnumerable<string> values)
        {
            return values
                .Where(v => !string.IsNullOrWhiteSpace(v))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();
        }

        /// <summary>
        /// Returns keys that are not in ownedKeys and not in additionalOwnedKeys.
        /// </summary>
        private static List<string> GetNonOwnedKeys(
            IEnumerable<string> targetKeys,
            ISet<string> ownedKeys,
            ISet<string> additionalOwnedKeys)
        {
            return targetKeys
                .Where(key => !ownedKeys.Contains(key) && !additionalOwnedKeys.Contains(key))
                .ToList();
        }

        /// <summary>
        /// For app quota entries where the user does not own the model traffic group,
        /// checks quota app ID ownership as a fallback. Returns the non-owned app IDs.
        /// </summary>
        private static List<string> GetNonOwnedQuotaAppIds(
            IEnumerable<(string MtgKey, string AppId)> appQuotaEntries,
            ISet<string> ownedModelTrafficGroups,
            ISet<string> glbsBeingCreated,
            ISet<string> ownedQuotaAppIds)
        {
            var nonOwned = new HashSet<string>(StringComparer.OrdinalIgnoreCase);

            foreach (var (mtgKey, appId) in appQuotaEntries)
            {
                if (string.IsNullOrWhiteSpace(appId))
                {
                    continue;
                }

                // If the user owns the model traffic group, they're authorized for this entry
                if (!string.IsNullOrWhiteSpace(mtgKey) &&
                    (ownedModelTrafficGroups.Contains(mtgKey) || glbsBeingCreated.Contains(mtgKey)))
                {
                    continue;
                }

                // Fall back to quota app ID ownership
                if (!HasOwnershipForAppId(appId, ownedQuotaAppIds))
                {
                    nonOwned.Add(appId);
                }
            }

            return nonOwned.ToList();
        }

        private static IEnumerable<string> GetServiceAuthQuotaAppIds(PapyrusConfigChangeSet changeSet)
        {
            if (changeSet == null)
            {
                yield break;
            }

            foreach (var command in changeSet.ServiceAuthQuotaCreateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementCreateCommand>())
            {
                yield return command.QuotaAppId;
            }

            foreach (var command in changeSet.ServiceAuthQuotaUpdateCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementUpdateCommand>())
            {
                yield return command.QuotaAppId;
            }

            foreach (var command in changeSet.ServiceAuthQuotaDeleteCommands ?? Enumerable.Empty<ServiceAuthQuotaManagementDeleteCommand>())
            {
                yield return command.QuotaAppId;
            }
        }

        /// <summary>
        /// Validates that the user has owner permission for the organizations associated with the given app IDs.
        /// </summary>
        /// <param name="user">The user claims principal.</param>
        /// <param name="appIds">The application IDs to check organization ownership for.</param>
        /// <param name="userAlias">The user's alias for error messages.</param>
        /// <returns>A validation result indicating success or failure with appropriate error message.</returns>
        private async Task<ValidationResult> ValidateOrganizationOwnershipAsync(ClaimsPrincipal user, IEnumerable<string> appIds, string userAlias)
        {
            var targetAppIds = (appIds ?? Enumerable.Empty<string>())
                .Where(id => !string.IsNullOrWhiteSpace(id))
                .Distinct(StringComparer.OrdinalIgnoreCase)
                .ToList();

            if (!targetAppIds.Any())
            {
                return new ValidationResult(true, null);
            }

            var quotas = await this.configSvc.GetServiceQuotaAndAuthManagementAsync(userAlias);
            var quotaOwnersLookup = (quotas ?? new List<ServiceAuthQuotaManagement>())
                .GroupBy(q => q.QuotaAppId, StringComparer.OrdinalIgnoreCase)
                .ToDictionary(
                    group => group.Key,
                    group => group
                        .SelectMany(q => q.Owners ?? Enumerable.Empty<string>())
                        .Distinct(StringComparer.OrdinalIgnoreCase)
                        .ToList(),
                    StringComparer.OrdinalIgnoreCase);

            var ownedAppIds = new HashSet<string>(
                quotaOwnersLookup.Keys
                    .Where(key => !string.IsNullOrWhiteSpace(key))
                    .Select(key => key.Trim()),
                StringComparer.OrdinalIgnoreCase);

            var missingQuotas = targetAppIds
                .Where(appId => !HasOwnershipForAppId(appId, ownedAppIds))
                .ToList();

            if (missingQuotas.Any())
            {
                var errors = new List<string>();

                if (missingQuotas.Any())
                {
                    errors.Add($"Quotas not found or not owned: [{string.Join(", ", missingQuotas)}]");
                }

                return new ValidationResult(false, string.Join(". ", errors));
            }

            return new ValidationResult(true, null);
        }

        private async Task<ValidationResult> ValidateDeploymentURLAsync(string url)
        {
            var urlWrapper = new DeploymentURLWrapper(url);
            if (urlWrapper.DeploymentURLType == DeploymentURLWrapper.DeploymentType.AML)
            {
                var exists = this.codexService.CheckEndpointInRegionExists(urlWrapper.URLTokens[0], urlWrapper.URLTokens[1]);
                if (!exists)
                {
                    return new ValidationResult(false, $"The following AML URL does not exist: {url}");
                }
            }

            if (urlWrapper.DeploymentURLType == DeploymentURLWrapper.DeploymentType.AOAI)
            {
                var accountName = urlWrapper.URLTokens[0];
                var deploymentName = urlWrapper.URLTokens[1];
                var deploymentExistsResult = await this.aoaiClient.CheckAoaiDeploymentExistAsync(this.aoaiClient.SubscriptionID, this.aoaiClient.ResourceGroup, accountName, deploymentName);
                if (!deploymentExistsResult.Result)
                {
                    return deploymentExistsResult;
                }
            }

            return new ValidationResult(true, "Success");
        }
    }
}

