public void UpdateEndpoint(string modelName, string trafficGroup, Endpoint endpoint, CommandContext commandContext)
{
    var config = this.GetModelTrafficGroupConfigJson(modelName, trafficGroup);
    var endpoints = config["ConfigData"]["EndpointConfigs"].AsArray();
    var foundEp = endpoints
            .Where(s => s["GlobalId"].GetValue<int>() == endpoint.GlobalId)
            .FirstOrDefault();
    if (foundEp == null)
    {
        throw new UserException($"Endpoint with GlobalId '{endpoint.GlobalId}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}' was not found in config config");
    }

    var parsedFoundEp = JsonSerializer.Deserialize<Endpoint>(foundEp.ToJsonString());
    if (parsedFoundEp == endpoint)
    {
        throw new UserException($"Attempting to update Endpoint with same exact values, GlobalId '{endpoint.GlobalId}', ModelName '{modelName}' & TrafficGroup '{trafficGroup}'");
    }

    var patchEQObject = JsonSerializer.SerializeToNode(endpoint, IgnoreNullJsonOptions).AsObject();
    var mergedObject = foundEp.AsObject().Merge(patchEQObject);
    if (endpoint.MaxConcurrencyPerInstance == null
        && mergedObject.ContainsKey("MaxConcurrencyPerInstance"))
    {
        mergedObject.Remove("MaxConcurrencyPerInstance");
    }

    if (endpoint.SafeConcurrencyPerInstance == null
        && mergedObject.ContainsKey("SafeConcurrencyPerInstance"))
    {
        mergedObject.Remove("SafeConcurrencyPerInstance");
    }

    foundEp.ReplaceWith(mergedObject);
    config["Hash"] = this.ComputeHash<ModelTrafficGroupConfigData>(config["ConfigData"]);

    var fileChanged = this.GetConfigFile(modelName, trafficGroup);
    commandContext.RegisterFileChange(fileChanged, PRFile.FileAction.Edit);
}

